/* AUTO-GENERATED by build-quests.ps1 - ordered questline steps, each anchored
   to the actual task location (item pickup / boss arena / NPC / area). */
window.QUESTLINES = [
  { id:"ranni", name:"Ranni the Witch", color:"#6f8fd6", steps:[
    { n:1, title:"Meet Renna", desc:"Speak with Renna atop the Church of Elleh to receive the Spirit Calling Bell and the Lone Wolf Ashes.", warn:"", kind:"npc", master:"M00", px:3678.3, py:7211.6 },
    { n:2, title:"Summon Blaidd", desc:"Answer Blaidd's howl by climbing to the ruins ledge in eastern Mistwood to begin his and Ranni's quests.", warn:"", kind:"npc", master:"M00", px:4415.5, py:7138.5 },
    { n:3, title:"Pledge to Ranni", desc:"Enter Ranni's service at Ranni's Rise in the Three Sisters, meeting Iji and Seluvis.", warn:"", kind:"npc", master:"M00", px:1611.3, py:3686.4 },
    { n:4, title:"Defeat Starscourge Radahn", desc:"Slay Radahn in Caelid so the falling star tears open the path down to Nokron.", warn:"Pledge to Ranni and answer Blaidd's howl BEFORE triggering the Radahn Festival (any Altus grace or Grand Lift of Dectus); else Blaidd vanishes and Ranni won't reappear at her Rise.", kind:"boss", master:"M00", px:6228.5, py:6825.9 },
    { n:5, title:"Enter Nokron", desc:"Drop into the new crater near Mistwood to descend into Nokron, Eternal City.", warn:"", kind:"grace", master:"M01", px:4549.9, py:6958 },
    { n:6, title:"Claim the Fingerslayer Blade", desc:"Take the Fingerslayer Blade from its chest in Nokron, then return it to Ranni for the Carian Inverted Statue.", warn:"Get the Magic Scorpion Charm from Seluvis (give him Amber Starlight) BEFORE returning the Fingerslayer Blade to Ranni; doing so kills Seluvis and locks the charm forever.", kind:"item", master:"M01", px:4873.2, py:6759.4 },
    { n:7, title:"Descend to Ainsel River", desc:"Use the waygate atop the now-open Renna's Rise to reach Ainsel River Main and loot the Miniature Ranni doll.", warn:"", kind:"grace", master:"M01", px:2709.5, py:4267.8 },
    { n:8, title:"Cross Nokstella", desc:"Travel through Nokstella, Eternal City to reach the Ainsel River's far depths.", warn:"", kind:"grace", master:"M01", px:2405.6, py:4460.5 },
    { n:9, title:"Defeat the Baleful Shadow", desc:"Slay the Blaidd-like Baleful Shadow near the Nokstella waterfall so Miniature Ranni grants the Discarded Palace Key.", warn:"", kind:"npc", master:"M01", px:2077.1, py:4515.1 },
    { n:10, title:"Brave the Lake of Rot", desc:"Cross the toxic Lake of Rot via the stepping stones to reach the Grand Cloister and Astel's coffin.", warn:"", kind:"grace", master:"M01", px:2072.5, py:4597.2 },
    { n:11, title:"Defeat Astel", desc:"Use the coffin in the Grand Cloister to confront and defeat Astel, Naturalborn of the Void.", warn:"", kind:"boss", master:"M01", px:1564, py:6141 },
    { n:12, title:"Dark Moon Ring", desc:"Open the Grand Library chest at Raya Lucaria with the Discarded Palace Key to claim the Dark Moon Ring.", warn:"", kind:"grace", master:"M00", px:1840.9, py:4818.3 },
    { n:13, title:"Age of the Stars", desc:"Place the Dark Moon Ring on Ranni at the Cathedral of Manus Celes to receive the Dark Moon Greatsword and choose the Age of the Stars ending.", warn:"", kind:"grace", master:"M00", px:1905.9, py:5783.9 },
  ]},
  { id:"millicent", name:"Millicent", color:"#d98ab0", steps:[
    { n:1, title:"Sage Gowry", desc:"Begin the quest at Gowry's Shack east of Aeonia Swamp in Caelid; he tasks you with recovering the Unalloyed Gold Needle.", warn:"Don't aggro the Giant Dog before the shack - it can follow you in and kill Gowry, permanently breaking the quest.", kind:"npc", master:"M00", px:5674.9, py:6737.8 },
    { n:2, title:"Defeat Commander O'Neil", desc:"Slay him in the tree-ringed portion of the Aeonia Swamp to obtain the Unalloyed Gold Needle.", warn:"", kind:"boss", master:"M00", px:5478.8, py:6733.4 },
    { n:3, title:"Return the Needle to Gowry", desc:"Give the needle to Gowry to mend, then reload and collect the repaired Unalloyed Gold Needle from him.", warn:"Give the needle to Gowry BEFORE talking to Millicent at the Church of the Plague, or Gowry can vanish and never repair it.", kind:"npc", master:"M00", px:5674.9, py:6737.8 },
    { n:4, title:"Deliver the Needle to Millicent", desc:"Hand the mended needle to the ailing Millicent at the Church of the Plague; she uses it herself, then awakens and grants the Prosthesis-Wearer Heirloom.", warn:"", kind:"grace", master:"M00", px:5779.9, py:6657 },
    { n:5, title:"Valkyrie's Prosthesis", desc:"Recover it from a chest guarded by a Cleanrot Knight inside the Shaded Castle in the northern Altus Plateau.", warn:"", kind:"item", master:"M00", px:2845.1, py:2621.5 },
    { n:6, title:"Restore Millicent", desc:"Give her the prosthesis where she stands north of Erdtree-Gazing Hill on the Altus Plateau.", warn:"", kind:"grace", master:"M00", px:2670.6, py:3389.1 },
    { n:7, title:"Aid Her at Windmill Village", desc:"Answer her golden summon sign to help defeat the Godskin Apostle at Dominula, Windmill Village, after which she journeys on through the Mountaintops toward the Haligtree.", warn:"After the Godskin Apostle, rest at the grace and exhaust Millicent's dialogue there before advancing, or progression can stall.", kind:"npc", master:"M00", px:3540.6, py:2612.3 },
    { n:8, title:"Aid or Oppose", desc:"At Elphael, defeat the nearby Putrid Tree Spirit, then choose her golden summon to fight her sisters alongside her or the red sign to challenge her alone.", warn:"One-time, irreversible choice: aiding gives Rotten Winged Sword Insignia; opposing gives only Millicent's Prosthesis. You can't get both.", kind:"grace", master:"M00", px:5585.2, py:772.4 },
    { n:9, title:"Millicent's End", desc:"Aiding her yields the Rotten Winged Sword Insignia (with the Unalloyed Gold Needle appearing on her body afterward); opposing her yields Millicent's Prosthesis.", warn:"", kind:"npc", master:"M00", px:5692.9, py:942.7 },
  ]},
  { id:"volcano", name:"Volcano Manor (Tanith)", color:"#c0504d", steps:[
    { n:1, title:"Recusant Invitation", desc:"Join Volcano Manor through Tanith and read the first Letter from Volcano Manor.", warn:"", kind:"npc", master:"M00", px:2227.4, py:2905.3 },
    { n:2, title:"Hunt: Old Knight Istvan", desc:"Use the red summon sign to invade and defeat Old Knight Istvan at the bridge near Warmaster's Shack, then report back to Tanith.", warn:"Finish all three hunts (Istvan, Rileigh, Juno) BEFORE killing Rykard - his death cancels any unfinished contracts.", kind:"grace", master:"M00", px:3720.3, py:6684.7 },
    { n:3, title:"Hunt: Rileigh the Idle", desc:"Read the second letter and invade Rileigh the Idle in the ravine to the Shaded Castle on the Altus Plateau, near the Bridge of Iniquity.", warn:"", kind:"npc", master:"M00", px:2880.1, py:2952.4 },
    { n:4, title:"Hunt: Juno Hoslow, Knight of Blood", desc:"Read the red letter and invade Juno Hoslow, Knight of Blood in the Mountaintops of the Giants.", warn:"Juno's invasion sign is in the Mountaintops of the Giants - you must progress past Leyndell to reach it, and do it before defeating Rykard.", kind:"npc", master:"M00", px:5803.9, py:2094.9 },
    { n:5, title:"Obtain the Serpent-Hunter", desc:"Grab the Serpent-Hunter great spear from the corpse on the left as you enter Rykard's arena via the Temple of Eiglay.", warn:"Grab the Serpent-Hunter spear from the corpse as you enter the arena - it is the intended way to kill Rykard and makes the fight far easier.", kind:"grace", master:"M00", px:2242.9, py:3041.9 },
    { n:6, title:"Defeat Rykard", desc:"Wield the Serpent-Hunter to slay Rykard, Lord of Blasphemy.", warn:"Defeating Rykard ends Volcano Manor progression: unfinished hunts are locked out and manor NPC quests (Rya, Bernahl, Patches) may vanish.", kind:"boss", master:"M00", px:2281.7, py:2952.4 },
    { n:7, title:"Tanith's Farewell", desc:"Return to Tanith, who consumes Rykard's remains and concludes the Volcano Manor questline.", warn:"", kind:"npc", master:"M00", px:2227.4, py:2905.3 },
  ]},
  { id:"fia", name:"Fia, Deathbed Companion", color:"#8e7cc3", steps:[
    { n:1, title:"Fia's Embrace", desc:"Accept her hold at the Roundtable Hold to receive Baldachin's Blessing, which boosts poise but lowers max HP.", warn:"Start Fia's quest BEFORE defeating Maliketh the Black-Blade. After that she's gone and the whole questline (and Duskborn ending) is locked out.", kind:"npc", master:"M00", px:2880.7, py:7627.1 },
    { n:2, title:"Weathered Dagger", desc:"Receive the Weathered Dagger from Fia and deliver it to D at the Roundtable Hold to advance the quest.", warn:"Burning the Erdtree sends Fia to Deeproot Depths early, skipping the Roundtable Hold steps (Weathered Dagger to D, Knifeprint/Rogier). Do these first.", kind:"npc", master:"M00", px:2843.5, py:7605.9 },
    { n:3, title:"Cursemark of Death", desc:"Obtain the Cursemark of Death atop the Divine Tower of Liurnia, reached by inverting the Carian Study Hall with Ranni's Carian Inverted Statue.", warn:"Needs Ranni's Carian Inverted Statue - advance Ranni's quest to delivering the Fingerslayer Blade (post-Nokron) before you can invert the Study Hall.", kind:"grace", master:"M00", px:3370.8, py:5130 },
    { n:4, title:"Deeproot Depths", desc:"Reach Deeproot Depths via Nokron's coffin route and give Fia the Cursemark of Death to receive the Radiant Baldachin's Blessing.", warn:"", kind:"grace", master:"M01", px:4232.6, py:3525.9 },
    { n:5, title:"Defeat Lichdragon Fortissax", desc:"Reload the area, then inspect the sleeping Fia to enter her Deathbed Dream and slay Lichdragon Fortissax.", warn:"Don't give D's brother the Twinned Armor (found before the Valiant Gargoyles) - it makes him kill Fia. The ending still works, but Fia dies.", kind:"boss", master:"M01", px:4382.2, py:3189.1 },
    { n:6, title:"Mending Rune of the Death-Prince", desc:"Loot the Mending Rune of the Death-Prince from Fia after the battle to unlock the Age of the Duskborn ending.", warn:"", kind:"item", master:"M01", px:4471.7, py:3107.5 },
  ]},
  { id:"dungeater", name:"Dung Eater", color:"#6b8e23", steps:[
    { n:1, title:"A Seething Plea", desc:"Meet the Dung Eater in the locked room beside the Twin Maiden Husks at Roundtable Hold, which opens after you reach the Altus Plateau.", warn:"The locked room beside the Twin Maiden Husks only opens once you have reached the Altus Plateau.", kind:"npc", master:"M00", px:2887.3, py:7561.3 },
    { n:2, title:"Show a Seedbed Curse", desc:"Approach him while holding any Seedbed Curse so he hands over the Sewer-Gaol Key and asks you to find his real body.", warn:"", kind:"grace", master:"M00", px:2841.2, py:7610 },
    { n:3, title:"Free His Bound Body", desc:"Use the Sewer-Gaol Key to unlock and free his imprisoned body deep in the Subterranean Shunning-Grounds beneath Leyndell.", warn:"Do NOT attack/kill his bound body in the cell before freeing it - killing it here softlocks the quest (no invasion, no completion).", kind:"grace", master:"M00", px:2351, py:2983 },
    { n:4, title:"Defeat His Invasion", desc:"Having freed him, return later to Leyndell's outer moat where he invades you; defeat him to claim the Sword of Milos.", warn:"Finish Blackguard Big Boggart's quest and grab his Seedbed Curse BEFORE this moat invasion, or his curse is lost forever.", kind:"npc", master:"M00", px:4299.6, py:3446.2 },
    { n:5, title:"Deliver Five Seedbed Curses", desc:"Bring five Seedbed Curses to his bound body back in the sewer cell to complete his quest.", warn:"Collect the Leyndell Seedbed Curses BEFORE defeating Maliketh - burning the Erdtree turns Leyndell to Ash and locks them out, risking quest completion.", kind:"grace", master:"M00", px:2351, py:2983 },
    { n:6, title:"Mending Rune of the Fell Curse", desc:"Receive the Mending Rune of the Fell Curse, after which reloading the area leaves the Omen armor set in his cell.", warn:"", kind:"item", master:"M00", px:4295.1, py:3439.7 },
  ]},
  { id:"nepheli", name:"Nepheli Loux", color:"#4a90d9", steps:[
    { n:1, title:"Stormveil Castle", desc:"Find Nepheli over a slain knight near the Liftside Chamber and exhaust her dialogue so she can be summoned against Godrick.", warn:"Exhaust her dialogue here BEFORE killing Godrick, or you can't summon her for the fight and the quest won't advance.", kind:"npc", master:"M00", px:3142.9, py:6599.2 },
    { n:2, title:"Defeat Godrick the Grafted", desc:"Summon Nepheli's golden sign before the fog and defeat Godrick to advance her quest.", warn:"", kind:"boss", master:"M00", px:3097.4, py:6460.4 },
    { n:3, title:"Roundtable Hold", desc:"Speak with Nepheli and Gideon at the Hold, receiving the Arsenal Charm talisman from her.", warn:"Do NOT give Nepheli Seluvis's potion - it puppets her and permanently locks out the rest of her quest.", kind:"grace", master:"M00", px:2841.2, py:7610 },
    { n:4, title:"Village of the Albinaurics", desc:"After she leaves the Hold, reunite with Nepheli beneath the bridge leading into the Village of the Albinaurics and exhaust her dialogue.", warn:"Talk to her under the bridge BEFORE killing the Omenkiller across the bridge above her, or you may miss this step.", kind:"grace", master:"M00", px:1714.2, py:5860.4 },
    { n:5, title:"Obtain the Stormhawk King", desc:"Retrieve the Stormhawk King spirit ashes from the Chapel of Anticipation (reached via the Four Belfries portal).", warn:"Needs an Imbued Sword Key to open the Four Belfries 'Precipice of Anticipation' portal; beat the Grafted Scion to reach the ashes.", kind:"grace", master:"M00", px:1471.4, py:4582 },
    { n:6, title:"Return to the Roundtable Hold", desc:"Give the Stormhawk King ashes to Nepheli, now back in the room outside the library, and exhaust her dialogue.", warn:"Give her the Stormhawk King BEFORE defeating Maliketh/burning the Erdtree - reaching Ashen Capital removes her and locks the quest.", kind:"npc", master:"M00", px:2855.1, py:7582.6 },
    { n:7, title:"Complete Kenneth Haight's quest", desc:"Finish Kenneth Haight's questline so he names Nepheli the rightful ruler of Limgrave, a prerequisite for her throne-room appearance.", warn:"", kind:"npc", master:"M00", px:4726.3, py:7298.1 },
    { n:8, title:"Defeat Morgott, the Omen King", desc:"Defeat Morgott in Leyndell to trigger Nepheli's relocation to Godrick's throne room (Maliketh must still be alive).", warn:"Morgott must be dead but Maliketh alive for the throne-room scene; don't kill Maliketh until the quest is finished.", kind:"boss", master:"M00", px:4564.4, py:3776.2 },
    { n:9, title:"Stormveil Throne Room", desc:"Return to Godrick's throne room and meet Nepheli (with Kenneth and Gostoc) to receive the Ancient Dragon Smithing Stone.", warn:"", kind:"npc", master:"M00", px:3046.4, py:6402.3 },
  ]},
  { id:"alexander", name:"Alexander, Iron Fist", color:"#e0883a", steps:[
    { n:1, title:"Stuck in a Hole", desc:"Free Alexander by striking him loose from a hole in Stormhill, north of Saintsbridge; he rewards Exalted Flesh and the Triumphant Delight gesture.", warn:"", kind:"grace", master:"M00", px:3988.9, py:6527.3 },
    { n:2, title:"Gael Tunnel", desc:"Find him stuck again at Gael Tunnel on the Limgrave-Caelid border, where he speaks of the Caelid festival.", warn:"", kind:"grace", master:"M00", px:4794.7, py:6437.8 },
    { n:3, title:"Radahn Festival", desc:"Summon him as a cooperator to fight alongside you against Radahn at Redmane Castle.", warn:"After defeating Radahn, return and exhaust his dialogue at the arena. Skipping this can leave him stuck at Redmane forever.", kind:"boss", master:"M00", px:6228.5, py:6825.9 },
    { n:4, title:"Exalted Flesh", desc:"Find him lodged in a hole south of Carian Study Hall in Liurnia, free him with an Oil Pot, and receive Exalted Flesh as he vows to harden himself at the fiery mount.", warn:"", kind:"grace", master:"M00", px:2904.8, py:5140.7 },
    { n:5, title:"Mt. Gelmir", desc:"Speak with him as he stands proudly in the lava pool near Seethewater Terminus, where he has come to temper his clay in the volcano's heat.", warn:"", kind:"grace", master:"M00", px:2046.2, py:2863.6 },
    { n:6, title:"Shard of Alexander", desc:"Win his final duel at Crumbling Farum Azula to claim the Shard of Alexander talisman.", warn:"Only the Farum Azula duel drops the Shard of Alexander. Killing him at any earlier location gives just the Warrior Jar Shard.  Â·  He only appears at Farum Azula after you defeat the Fire Giant and complete his earlier steps in order.", kind:"item", master:"M00", px:2843.5, py:7605.9 },
  ]},
  { id:"goldmask", name:"Goldmask & Corhyn", color:"#cbb12b", steps:[
    { n:1, title:"Brother Corhyn", desc:"Meet Corhyn studying incantations at the Roundtable Hold.", warn:"", kind:"npc", master:"M00", px:2838.1, py:7600.6 },
    { n:2, title:"Find Goldmask", desc:"Locate the silent Goldmask on the Forest-Spanning Greatbridge in northern Altus Plateau.", warn:"", kind:"npc", master:"M00", px:3273.2, py:2659.3 },
    { n:3, title:"Reunite the Pair", desc:"Tell Corhyn (north of Altus Highway Junction) of Goldmask's whereabouts so he joins him.", warn:"", kind:"npc", master:"M00", px:3082, py:3278.8 },
    { n:4, title:"Toward the Capital", desc:"Both relocate to Leyndell, where Goldmask ponders Radagon's true identity.", warn:"", kind:"npc", master:"M00", px:4251.2, py:3781.7 },
    { n:5, title:"Law of Regression", desc:"Retrieve the Golden Order Principia from a corpse on a hanging chair above the Erdtree Sanctuary Site of Grace in Leyndell (climb the roots and enter through the rooftop window), then learn Law of Regression from Corhyn or Miriel.", warn:"Get the Principia and learn Law of Regression BEFORE burning the Erdtree (Forge of the Giants, after Fire Giant), or Corhyn vanishes and the quest is lost.", kind:"grace", master:"M00", px:4365, py:3707.5 },
    { n:6, title:"Reveal the Truth", desc:"Cast Law of Regression on Radagon's statue in Leyndell to expose Marika and Radagon as one, then report the truth to Goldmask, who awards the Golden Order Totality gesture.", warn:"Cast Law of Regression on Radagon's statue BEFORE burning the Erdtree. Burning it first makes Corhyn leave only his Bell Bearing - quest cannot be finished.", kind:"npc", master:"M00", px:4251.2, py:3781.7 },
    { n:7, title:"Mountaintops Meeting", desc:"Find the pair on a great bridge in the Mountaintops of the Giants as Goldmask weighs the Order's flaws.", warn:"", kind:"npc", master:"M00", px:6024.6, py:2219.7 },
    { n:8, title:"Mending Rune of Perfect Order", desc:"In Leyndell, Capital of Ash, loot the Mending Rune from Goldmask's body for the Age of Order ending.", warn:"Goldmask's corpse only appears in Leyndell, Capital of Ash after you complete Crumbling Farum Azula (defeat Maliketh). Loot the rune then.", kind:"grace", master:"M00", px:4365.5, py:3448.4 },
  ]},
  { id:"yura", name:"Yura, Hunter of Bloody Fingers", color:"#8b1a1a", steps:[
    { n:1, title:"Meet Yura at Agheel Lake", desc:"Travel northeast from the Seaside Ruins grace toward Agheel Lake to find Yura resting beneath a tunnel-like overpass and speak with him.", warn:"You must speak to Yura here at least once, or he won't relocate to Raya Lucaria and the quest can't advance.", kind:"npc", master:"M00", px:4005.6, py:7482.4 },
    { n:2, title:"Survive the Nerijus invasion", desc:"Approach Murkwater Cave where Bloody Finger Nerijus invades, and summon Yura's white sign to help you defeat him.", warn:"", kind:"boss", master:"M00", px:4084.4, py:6999.8 },
    { n:3, title:"Obtain Reduvia", desc:"Defeat Bloody Finger Nerijus during the invasion to receive the Reduvia bleed dagger as a drop.", warn:"", kind:"item", master:"M00", px:4084.4, py:6999.8 },
    { n:4, title:"Speak with Yura after the invasion", desc:"Find Yura under a tunnel-like ruin directly north of Murkwater Cave, where he explains his mission to hunt Bloody Fingers.", warn:"", kind:"npc", master:"M00", px:4085.4, py:6850.9 },
    { n:5, title:"Answer Yura's summon at Raya Lucaria", desc:"Cross into Liurnia and use Yura's red summon sign at the Main Academy Gate to enter his world against the Bloody Finger Ravenmount Assassin.", warn:"", kind:"grace", master:"M00", px:1827, py:4769 },
    { n:6, title:"Talk to Yura after the cooperation", desc:"After defeating the Ravenmount Assassin, speak with Yura near the Main Academy Gate to receive Ash of War: Raptor of the Mists and a Smithing Stone [5].", warn:"", kind:"npc", master:"M00", px:1860.8, py:4704 },
    { n:7, title:"Find the dying Yura at the Second Church of Marika", desc:"Travel to the Second Church of Marika in the Altus Plateau and speak to the mortally wounded Yura, who was bested by Eleonora.", warn:"Do before taking the Grand Lift of Rold. Yura vanishes (possessed by Shabriri) once you enter the Rold Lift hall.", kind:"npc", master:"M00", px:1860.8, py:4704 },
    { n:8, title:"Obtain the Nagakiba", desc:"Receive the Nagakiba katana dropped by the dying Yura at the Second Church of Marika.", warn:"If Yura is possessed before you reach him here, loot the Nagakiba from his initial Agheel Lake spot, the pass below Murkwater Coast, or the bridge near Main Academy Gate.", kind:"item", master:"M00", px:1860.8, py:4704 },
    { n:9, title:"Trigger Eleonora's invasion", desc:"Speaking to the dying Yura activates the invasion of Eleonora, Violet Bloody Finger, at the Second Church of Marika.", warn:"", kind:"npc", master:"M00", px:2961, py:3142.8 },
    { n:10, title:"Defeat Eleonora and claim the reward", desc:"Defeat Eleonora, Violet Bloody Finger to obtain Eleonora's Poleblade and the Purifying Crystal Tear, completing Yura's quest.", warn:"Reach the dying Yura before the Grand Lift of Rold; if he's possessed first, this Eleonora invasion (Poleblade + Purifying Crystal Tear) is lost.", kind:"item", master:"M00", px:2944, py:3200 },
  ]},
  { id:"patches", name:"Patches", color:"#7a8c4a", steps:[
    { n:1, title:"Enter Murkwater Cave", desc:"Follow the river running north from Agheel Lake in Limgrave into Murkwater Cave, then open the chest at the rear of the cave to trigger the Patches boss fight.", warn:"", kind:"grace", master:"M00", px:4010.5, py:6986 },
    { n:2, title:"Spare Patches when he surrenders", desc:"Fight Patches until he begs for mercy at roughly half health, then stop attacking to accept his surrender, which teaches the Grovel for Mercy gesture and opens his shop instead of killing him.", warn:"Stop attacking when he begs. Killing Patches here permanently ends his quest and removes him as a merchant for the whole playthrough.", kind:"npc", master:"M00", px:4008.6, py:6970.7 },
    { n:3, title:"Open the trapped chest to Mistwood", desc:"Return to Patches' shop and ask about the new chest he offers, which springs a trap and teleports you near the Mistwood Ruins in eastern Limgrave.", warn:"", kind:"grace", master:"M00", px:4010.5, py:6986 },
    { n:4, title:"Return and earn the Calm Down gesture", desc:"Travel back to Murkwater Cave and speak with Patches again after the chest trap to receive the Calm Down gesture and continue the questline.", warn:"", kind:"npc", master:"M00", px:4008.6, py:6970.7 },
    { n:5, title:"Find Patches at Scenic Isle", desc:"Enter Liurnia of the Lakes, where Patches has relocated to set up shop beside the Scenic Isle Site of Grace in the southern swamp.", warn:"", kind:"grace", master:"M00", px:2333.8, py:5735 },
    { n:6, title:"Hear Patches' Abductor Virgin tip", desc:"Speak with Patches at Scenic Isle so he tells you about the Abductor Virgin at the Academy of Raya Lucaria that he claims will transport you to the foot of the Erdtree.", warn:"", kind:"npc", master:"M00", px:2340.2, py:5728 },
    { n:7, title:"Get abducted toward Volcano Manor", desc:"Let the Abductor Virgin at the Academy of Raya Lucaria capture and kill you, which actually delivers you to the prison cells beneath Volcano Manor on Mt. Gelmir.", warn:"", kind:"grace", master:"M00", px:1885, py:4928.8 },
    { n:8, title:"Reach Patches' Mt. Gelmir cliff", desc:"On Mt. Gelmir, follow the trail of rainbow stones near the First Mt. Gelmir Campsite to the cliff edge, where Patches appears and kicks you off while warning you away from Volcano Manor.", warn:"", kind:"grace", master:"M00", px:2716.2, py:2811.3 },
    { n:9, title:"Join Volcano Manor under Tanith", desc:"Enter Volcano Manor and accept Lady Tanith's invitation to join the Recusants, after which Patches sets up shop in the entrance hallway before the Volcano Manor grace.", warn:"", kind:"npc", master:"M00", px:2227.4, py:2905.3 },
    { n:10, title:"Receive the Letter to Patches", desc:"After completing Tanith's first assassination request against Old Knight Istvan, speak to Patches in the Volcano Manor hallway to receive the Letter to Patches naming Great-Horned Tragoth as the target.", warn:"", kind:"npc", master:"M00", px:2215.8, py:2867.1 },
    { n:11, title:"Invade and kill Great-Horned Tragoth", desc:"Rest at the Magma Wyrm Makar grace in the Ruin-Strewn Precipice and use the red summon sign in that boss room to invade and defeat Great-Horned Tragoth, who drops the Bull-Goat armor set.", warn:"", kind:"grace", master:"M00", px:2572.3, py:3607 },
    { n:12, title:"Claim the Magma Whip Candlestick", desc:"Return to Patches at Volcano Manor and reload the area, then speak to him to receive the Magma Whip Candlestick before he leaves once Rykard is slain.", warn:"Get the Magma Whip Candlestick BEFORE defeating Rykard (step 13). Patches leaves the manor once Rykard dies and it is lost otherwise.", kind:"item", master:"M00", px:2228.9, py:2894.3 },
    { n:13, title:"Defeat Rykard to empty the manor", desc:"Defeat Rykard, Lord of Blasphemy at Volcano Manor, after which Patches and the other residents abandon the manor.", warn:"", kind:"boss", master:"M00", px:2281.7, py:2952.4 },
    { n:14, title:"Find injured Patches at Shaded Castle", desc:"Travel to the Shaded Castle in northern Altus Plateau and find Patches lying injured on the walkway before the Elemer of the Briar boss room, where he entrusts you with the Dancer's Castanets.", warn:"", kind:"grace", master:"M00", px:2893.1, py:2639.9 },
    { n:15, title:"Deliver the Dancer's Castanets to Tanith", desc:"Bring the Dancer's Castanets that Patches entrusted to you back to Tanith at Volcano Manor to fulfill his request on his behalf.", warn:"Tanith must still be present to receive the Castanets. If she is killed/gone, this delivery can no longer be completed.", kind:"npc", master:"M00", px:2227.4, py:2905.3 },
    { n:16, title:"Confront Patches one last time at Murkwater Cave", desc:"Return to Murkwater Cave, where Patches reappears as a boss but stops fighting once he recognizes you, teaching the Patches' Crouch gesture.", warn:"", kind:"npc", master:"M00", px:4008.6, py:6970.7 },
    { n:17, title:"Reload to reopen Patches' shop", desc:"Reload the Murkwater Cave area after the final encounter so Patches sits back down and permanently reopens his shop.", warn:"", kind:"grace", master:"M00", px:4010.5, py:6986 },
  ]},
  { id:"sellen", name:"Sorceress Sellen", color:"#5b6fd6", steps:[
    { n:1, title:"Find Sellen in the Waypoint Ruins", desc:"Descend into the cellar at the Waypoint Ruins in eastern Limgrave, defeat the Mad Pumpkin Head guarding the door, then open it to meet Sorceress Sellen and become her apprentice.", warn:"", kind:"npc", master:"M00", px:4242, py:7276.9 },
    { n:2, title:"Accept Sellen's task to find Azur", desc:"Exhaust Sellen's dialogue and accept her request to seek the Primeval Sorcerers, beginning with Azur in Mt. Gelmir.", warn:"", kind:"npc", master:"M00", px:4242, py:7276.9 },
    { n:3, title:"Learn Comet Azur from Primeval Sorcerer Azur", desc:"Travel to the Hermit Village area on Mt. Gelmir and interact with the seated Primeval Sorcerer Azur to receive the Comet Azur sorcery.", warn:"", kind:"npc", master:"M00", px:2437, py:3013.5 },
    { n:4, title:"Report Azur's fate back to Sellen", desc:"Return to Sellen at the Waypoint Ruins, tell her of Azur, and accept her request to find Master Lusat, receiving the glintstone key needed to reach him.", warn:"", kind:"npc", master:"M00", px:4242, py:7276.9 },
    { n:5, title:"Enter Sellia Hideaway in Caelid", desc:"Reach the Sellia Hideaway behind Sellia, Town of Sorcery, and use Sellen's glintstone key to lower the magic barrier blocking the cave's depths.", warn:"", kind:"grace", master:"M00", px:5900.4, py:6435.7 },
    { n:6, title:"Learn Stars of Ruin from Primeval Sorcerer Lusat", desc:"Pass the illusory wall and open the sealed door deep in Sellia Hideaway, then interact with the imprisoned Primeval Sorcerer Lusat to receive the Stars of Ruin sorcery.", warn:"", kind:"npc", master:"M00", px:5779.8, py:6358.5 },
    { n:7, title:"Report Lusat's fate back to Sellen", desc:"Return to Sellen at the Waypoint Ruins and exhaust her dialogue about Lusat to advance the questline.", warn:"", kind:"npc", master:"M00", px:4242, py:7276.9 },
    { n:8, title:"Defeat Starscourge Radahn", desc:"Progress to Redmane Castle and defeat Starscourge Radahn, after which Sellen tasks you to meet her at Witchbane Ruins before vanishing from the Waypoint Ruins.", warn:"", kind:"boss", master:"M00", px:6228.5, py:6825.9 },
    { n:9, title:"Recover Sellen's Primal Glintstone", desc:"Travel to Witchbane Ruins in the Weeping Peninsula, descend into the cellar, and free the bound Sellen who entrusts you with Sellen's Primal Glintstone.", warn:"Don't fast-travel/rest while collecting the Primal Glintstone - it can kill Sellen and stall the quest. Quit to reload if she dies.  Â·  Do NOT attack Sellen here - it stalls her quest and breaks her merchant role; only Church of Vows absolution can undo it.", kind:"item", master:"M00", px:3857.3, py:7695.9 },
    { n:10, title:"Speak with Witch-Hunter Jerren at Redmane Castle", desc:"Return to the throne room of Redmane Castle, exhaust Witch-Hunter Jerren's dialogue about hunting Sellen, then rest at a Site of Grace to reset the area.", warn:"", kind:"npc", master:"M00", px:1887.2, py:4837.2 },
    { n:11, title:"Confront Jerren over Sellen at Witchbane Ruins", desc:"Go back to Witchbane Ruins to find Witch-Hunter Jerren standing over Sellen's broken body and exhaust his dialogue to unlock the next step.", warn:"", kind:"npc", master:"M00", px:1887.2, py:4837.2 },
    { n:12, title:"Find Seluvis's hidden basement at Three Sisters", desc:"Go to the ruins on the right of the approach up to Ranni's Rise in the Three Sisters and strike the illusory floor between the pillars to reveal Seluvis's hidden cellar.", warn:"", kind:"grace", master:"M00", px:1578.7, py:3698.2 },
    { n:13, title:"Transplant Sellen into the new puppet body", desc:"Behind the illusory wall past Seluvis's puppet, insert Sellen's Primal Glintstone into the doll to restore her, after which she sells sorceries from this spot.", warn:"", kind:"npc", master:"M00", px:1660.3, py:3670.2 },
    { n:14, title:"Defeat Rennala, Queen of the Full Moon", desc:"Clear Raya Lucaria Academy and defeat Rennala in the Grand Library to gain access to the room where Sellen's finale takes place.", warn:"", kind:"boss", master:"M00", px:1878.4, py:4821.4 },
    { n:15, title:"Confront Witch-Hunter Jerren at the Grand Library", desc:"Return to the Raya Lucaria Grand Library to find Sellen confronted by Witch-Hunter Jerren, with two summon signs near the boss-room doors that decide her fate.", warn:"", kind:"npc", master:"M00", px:1887.2, py:4837.2 },
    { n:16, title:"Ending A - Aid Sellen against Jerren", desc:"Use the gold summon sign to help Sellen defeat Witch-Hunter Jerren, after which she rewards you with the Glintstone Kris dagger and adds the Shard Spiral sorcery to her shop.", warn:"", kind:"npc", master:"M00", px:1887.2, py:4837.2 },
    { n:17, title:"Ending A - Claim the Eccentric Set and Crown", desc:"After the victory Sellen becomes a School of Graven Mages mass dropping the Witch's Glintstone Crown beside her, and looting the defeated Jerren's corpse yields the Eccentric armor set.", warn:"", kind:"item", master:"M00", px:2843.5, py:7605.9 },
    { n:18, title:"Ending B - Side with Jerren and kill Sellen", desc:"Alternatively use the red summon sign to slay Sorceress Sellen for the Witch's Glintstone Crown, Sellen's Bell Bearing, and a Rune Arc, then speak to Jerren for an Ancient Dragon Smithing Stone.", warn:"Siding with Jerren (red sign) permanently locks Lusat's Set, Azur's Set, Glintstone Kris and Shard Spiral until NG+. Pick the gold sign to keep them.", kind:"npc", master:"M00", px:1849.8, py:4821.5 },
  ]},
  { id:"hyetta", name:"Hyetta (Frenzied Flame)", color:"#d98a3a", steps:[
    { n:1, title:"Progress Irina and Edgar's quest to unlock Hyetta", desc:"Deliver Irina's letter to Castellan Edgar and progress their questline so Edgar witnesses Irina's corpse, the trigger that makes Hyetta appear in Liurnia.", warn:"Talk to Irina first - killing her before getting her letter permanently stops Hyetta from ever appearing.", kind:"npc", master:"M00", px:4376, py:7847.1 },
    { n:2, title:"Obtain the first Shabriri Grape in Stormveil Castle", desc:"After defeating Godrick the Grafted, descend into the basement beneath his throne room to collect the first Shabriri Grape.", warn:"", kind:"item", master:"M00", px:3032.6, py:6383.7 },
    { n:3, title:"Feed Hyetta her first grape at Lake-Facing Cliffs", desc:"Find the blind Hyetta near the cliffside and give her the first Shabriri Grape, earning the 'As You Wish' gesture.", warn:"", kind:"npc", master:"M00", px:4634.6, py:3398.8 },
    { n:4, title:"Feed Hyetta her second grape at Purified Ruins", desc:"Find Hyetta at Purified Ruins and give her a second Shabriri Grape obtained from the hidden lower level there, reached by breaking the wooden planks covering a staircase.", warn:"", kind:"npc", master:"M00", px:4634.6, py:3398.8 },
    { n:5, title:"Kill Edgar the Revenger for a Shabriri Grape", desc:"Defeat Edgar the Revenger at Revenger's Shack on the western edge of Liurnia to claim the third Shabriri Grape.", warn:"", kind:"npc", master:"M00", px:1427.2, py:5221.1 },
    { n:6, title:"Feed Hyetta her third grape near Gate Town Bridge", desc:"Give Hyetta the third Shabriri Grape where she waits near Gate Town Bridge, then choose the dialogue telling her the grapes are truly human eyes to advance the quest.", warn:"", kind:"npc", master:"M00", px:4634.6, py:3398.8 },
    { n:7, title:"Defeat Festering Fingerprint Vyke for the Fingerprint Grape", desc:"Travel to the Church of Inhibition in northeastern Liurnia, survive Vyke's Bloody Finger invasion, and take the Fingerprint Grape he drops.", warn:"", kind:"npc", master:"M00", px:2505.3, py:4051.1 },
    { n:8, title:"Give Hyetta the Fingerprint Grape at Bellum Church", desc:"Bring the Fingerprint Grape to Hyetta at Bellum Church in northeastern Liurnia, after which she thanks you and departs.", warn:"", kind:"npc", master:"M00", px:4634.6, py:3398.8 },
    { n:9, title:"Accept the Three Fingers' flame", desc:"Descend beneath Leyndell to the Frenzied Flame Proscription, exhaust Hyetta's dialogue, strip off all armor and weapons, then pass through the sealed door and accept the Three Fingers.", warn:"Accepting the flame locks you into the Frenzied Flame ending; only undoable via Miquella's Needle (requires beating Malenia).  Â·  Accept it BEFORE the Forge of the Giants cutscene to spare Melina; doing so after changes the burning-Erdtree outcome.", kind:"npc", master:"M00", px:2193.2, py:4048.3 },
    { n:10, title:"Speak with Hyetta to complete the quest and claim the reward", desc:"After accepting the flame, talk to Hyetta again at the Frenzied Flame Proscription, and the Frenzied Flame Seal plus five Frenzyflame Stones appear to complete her questline.", warn:"", kind:"npc", master:"M00", px:2193.2, py:4048.3 },
    { n:11, title:"Pick up the Frenzied Flame Seal", desc:"Collect the Frenzied Flame Seal that appears on the ground, the unique sacred seal scaling with Faith, Strength, and Dexterity that boosts Frenzied Flame incantations.", warn:"", kind:"item", master:"M00", px:2843.5, py:7605.9 },
  ]},
  { id:"latenna", name:"Latenna the Albinauric", color:"#6fb1c4", steps:[
    { n:1, title:"Find Albus at the Village of the Albinaurics", desc:"Travel to the Village of the Albinaurics in western Liurnia and walk up the path from the grace past the Depraved Perfumer to find Albus hiding disguised as a large pot.", warn:"", kind:"grace", master:"M00", px:1714.2, py:5860.4 },
    { n:2, title:"Reveal Albus and receive the Haligtree Secret Medallion (Right)", desc:"Strike the disguised pot to reveal Albus and speak with him to obtain the Haligtree Secret Medallion (Right), the key item needed to win Latenna's trust.", warn:"", kind:"item", master:"M00", px:1817.7, py:5877.4 },
    { n:3, title:"Clear the Lakeside Crystal Cave", desc:"Enter the Lakeside Crystal Cave on the southern shore of Liurnia and fight through its depths to defeat the Bloodhound Knight boss guarding the far exit.", warn:"", kind:"grace", master:"M00", px:2315.9, py:6020.4 },
    { n:4, title:"Reach the Slumbering Wolf's Shack", desc:"Pass through the boss arena to emerge in a secluded clearing and rest at the Slumbering Wolf's Shack Site of Grace.", warn:"", kind:"grace", master:"M00", px:2315.3, py:6078.9 },
    { n:5, title:"Meet Latenna and show the medallion", desc:"Approach Latenna seated beside the shack with her wolf Lobo and present the Haligtree Secret Medallion (Right) to earn her trust.", warn:"Do NOT kill Latenna at the shack - she drops no spirit ash, permanently losing the summon and the Somber Ancient Dragon Smithing Stone reward.", kind:"npc", master:"M00", px:2307.3, py:6076.3 },
    { n:6, title:"Hear Latenna's request and accept her", desc:"Exhaust Latenna's dialogue as she asks to be shown the way to Miquella's Haligtree and mentions the medallion's other half, then accept her into your service.", warn:"", kind:"npc", master:"M00", px:2307.3, py:6076.3 },
    { n:7, title:"Obtain the Latenna spirit ash", desc:"Receive the Latenna the Albinauric spirit summon from her, allowing you to carry her spirit across the Lands Between.", warn:"Recruit Latenna and grab her spirit ash BEFORE taking the Grand Lift of Rold into the Consecrated Snowfield, or the quest breaks.", kind:"item", master:"M00", px:2315.3, py:6078.9 },
    { n:8, title:"Bring Latenna to the Apostate Derelict", desc:"Travel to the Apostate Derelict in the northwest of the Consecrated Snowfield where a giant slumbering Albinauric woman rests.", warn:"", kind:"grace", master:"M00", px:5042.9, py:1696.3 },
    { n:9, title:"Summon Latenna at the Apostate Derelict", desc:"Summon the Latenna spirit beside the giant Albinauric woman and exhaust the resulting dialogue to complete her journey home.", warn:"", kind:"npc", master:"M00", px:5026.7, py:1673.7 },
    { n:10, title:"Receive the Somber Ancient Dragon Smithing Stone", desc:"Claim the Somber Ancient Dragon Smithing Stone given by Latenna as the reward for fulfilling her final wish.", warn:"", kind:"item", master:"M00", px:5026.7, py:1673.7 },
  ]},
  { id:"diallos", name:"Diallos and Jarburg", color:"#b0884a", steps:[
    { n:1, title:"Meet Diallos at the Roundtable Hold", desc:"Speak with Knight Diallos at the Roundtable Hold, where he frets over his missing servant Lanya and asks you to keep an eye out for her.", warn:"", kind:"npc", master:"M00", px:2850.1, py:7607.5 },
    { n:2, title:"Find Diallos in northern Liurnia", desc:"Track Diallos to a sunken rooftop north and slightly west of the Academy Gate Town grace and speak with him before ever completing Volcano Manor.", warn:"Do this BEFORE completing Volcano Manor. If you finish the Manor first, Diallos never appears here and the quest is permanently lost.", kind:"npc", master:"M00", px:2370.7, py:5191.3 },
    { n:3, title:"Hear Diallos's plan back at the Roundtable", desc:"Return to the Roundtable Hold and speak with Diallos, who reveals he has traced the Recusants and intends to infiltrate them.", warn:"", kind:"npc", master:"M00", px:2850.1, py:7607.5 },
    { n:4, title:"Find Diallos at Volcano Manor", desc:"Reach Volcano Manor and find Diallos in the drawing room alongside Bernahl, then exhaust his dialogue.", warn:"", kind:"npc", master:"M00", px:2193.7, py:2925 },
    { n:5, title:"Complete the first assassination Letter", desc:"Take the first Letter from Volcano Manor and slay Old Knight Istvan, then return to hear Diallos grow more disillusioned.", warn:"", kind:"npc", master:"M00", px:3652.9, py:6420 },
    { n:6, title:"Accept the second Letter to make Diallos leave", desc:"Accept the second Letter from Volcano Manor targeting Rileigh the Idle, after which a despairing Diallos abandons the Manor.", warn:"", kind:"npc", master:"M00", px:2880.1, py:2952.4 },
    { n:7, title:"Defeat Rykard, Lord of Blasphemy", desc:"Slay Rykard within Volcano Manor to conclude the Manor chapter, which alternatively also forces Diallos to leave.", warn:"", kind:"boss", master:"M00", px:2281.7, py:2952.4 },
    { n:8, title:"Meet Jar-Bairn in Jarburg", desc:"Travel to Jarburg, southeast of the Artist's Shack in Liurnia, and speak with Jar-Bairn about his wish to become a Potentate.", warn:"Never attack or destroy the living jars in Jarburg - doing so angers Jar-Bairn and permanently breaks this questline.", kind:"npc", master:"M00", px:2966.1, py:5274.9 },
    { n:9, title:"Exhaust Jar-Bairn's dialogue and reset", desc:"Repeatedly rest at the Jarburg Site of Grace and re-speak with Jar-Bairn to advance his dialogue toward Diallos's arrival.", warn:"", kind:"grace", master:"M00", px:2991, py:5307 },
    { n:10, title:"Find Diallos kneeling as the new Potentate", desc:"After resetting Jarburg, discover Diallos tending a jar inside a hut at the end of the village as its new Potentate.", warn:"", kind:"npc", master:"M00", px:2370.7, py:5191.3 },
    { n:11, title:"Optional: meet Alexander at the Radahn arena", desc:"Optionally visit Starscourge Radahn's arena at the Wailing Dunes to exhaust Alexander, Warrior Jar's dialogue. This is not required for Jarburg - only Rykard's defeat (step 7) matters; the poacher attack triggers from exhausting Diallos's and Jar-Bairn's dialogue and reloading the area at night.", warn:"", kind:"boss", master:"M00", px:6228.5, py:6825.9 },
    { n:12, title:"Rest at the Starscourge Radahn grace and return", desc:"Rest at the Starscourge Radahn Site of Grace and travel back to Jarburg, then exhaust both Diallos's and Jar-Bairn's dialogue to set off the poacher attack.", warn:"Poacher attack only triggers after Radahn is defeated and Alexander's dialogue exhausted; needs nighttime plus a map reload (grace rest/fast travel).", kind:"grace", master:"M00", px:6228.5, py:6825.9 },
    { n:13, title:"Witness Diallos's last stand", desc:"Return to a ransacked Jarburg and speak with the fatally wounded Diallos amid the smashed jars as he asks whether he protected the village.", warn:"", kind:"npc", master:"M00", px:2370.7, py:5191.3 },
    { n:14, title:"Mourn Diallos with Jar-Bairn", desc:"Rest at the grace and return to speak with Jar-Bairn grieving beside Diallos's fallen body.", warn:"", kind:"npc", master:"M00", px:2966.1, py:5274.9 },
    { n:15, title:"Collect Diallos's bequest", desc:"After reloading, claim the items left where Diallos fell, including Hoslow's Petal Whip, Diallos's Mask, and a Numen's Rune.", warn:"", kind:"item", master:"M00", px:2987.3, py:5243.2 },
    { n:16, title:"Give Alexander's Innards to Jar-Bairn", desc:"Hand Jar-Bairn the Alexander's Innards earned from Alexander's questline in Crumbling Farum Azula to close the tale and receive the Companion Jar talisman.", warn:"Requires completing Alexander's full quest into Crumbling Farum Azula. Miss Alexander's questline and you forfeit the Companion Jar talisman.", kind:"item", master:"M00", px:2991, py:5307 },
  ]},
  { id:"boc", name:"Boc the Seamster", color:"#5fb878", steps:[
    { n:1, title:"Find the talking tree in Limgrave", desc:"East of the Birdseye Telescope south of Agheel Lake North, strike the small talking tree to break the spell and free Boc the Seamster, who rewards you with 10 Mushrooms.", warn:"", kind:"npc", master:"M00", px:2956.2, py:6346 },
    { n:2, title:"Find Boc injured at Coastal Cave", desc:"Travel to the Coastal Cave on Limgrave's western shore and speak with the wounded Boc lying outside the entrance.", warn:"", kind:"npc", master:"M00", px:2956.2, py:6346 },
    { n:3, title:"Defeat the Demi-Human Chiefs", desc:"Enter the Coastal Cave and defeat the duo of Demi-Human Chiefs guarding Boc's stolen belongings.", warn:"", kind:"grace", master:"M00", px:3501.8, py:7314.7 },
    { n:4, title:"Obtain the Sewing Needle and Tailoring Tools", desc:"Claim the Sewing Needle and Tailoring Tools dropped after the Demi-Human Chief fight.", warn:"", kind:"item", master:"M00", px:3486.9, py:7395.9 },
    { n:5, title:"Return the tools to Boc", desc:"Give the Sewing Needle and Tailoring Tools back to Boc outside the cave so he becomes your seamster, then rest at a grace to send him onward.", warn:"", kind:"npc", master:"M00", px:2956.2, py:6346 },
    { n:6, title:"Reunite with Boc in Liurnia", desc:"Find Boc at the Lake-Facing Cliffs in Liurnia of the Lakes and speak with him to unlock free garment alterations.", warn:"", kind:"npc", master:"M00", px:2956.2, py:6346 },
    { n:7, title:"Acquire the Gold Sewing Needle", desc:"Obtain the Gold Sewing Needle from the Church of Vows in eastern Liurnia, the special needle Boc longs to work with.", warn:"", kind:"item", master:"M00", px:2369.9, py:4717.6 },
    { n:8, title:"Give Boc the Gold Sewing Needle at East Raya Lucaria Gate", desc:"Meet Boc again near the East Raya Lucaria Gate and give him the Gold Sewing Needle, which he marvels at as a royal-crested treasure.", warn:"Boc only alters demigod armor, so the Gold Needle path needs legendary/demigod armor in your inventory (e.g. Radahn's) to progress.", kind:"npc", master:"M00", px:2091.1, py:4314.6 },
    { n:9, title:"Find Boc at Altus Highway Junction", desc:"Progress to the Altus Plateau and find Boc resting at the Altus Highway Junction Site of Grace.", warn:"", kind:"npc", master:"M00", px:3039.4, py:3450.8 },
    { n:10, title:"Meet Boc in Leyndell", desc:"Reach Leyndell, Royal Capital and find Boc at the East Capital Rampart Site of Grace, where he despairs over his demi-human appearance and asks for a Larval Tear to be reborn.", warn:"After burning the Erdtree, Boc's map icon vanishes; he's still at East Capital Rampart - go there and re-light the grace to continue.", kind:"npc", master:"M00", px:4457.8, py:3404.6 },
    { n:11, title:"Obtain the You're Beautiful Prattling Pate", desc:"Collect the \"You're Beautiful\" Prattling Pate from Hermit Village on Mount Gelmir to save Boc from his fatal wish.", warn:"", kind:"item", master:"M00", px:2436.9, py:3113.9 },
    { n:12, title:"Tell Boc he is beautiful", desc:"At the East Capital Rampart, play the \"You're Beautiful\" Prattling Pate so Boc hears his mother's voice, then agree that he is beautiful, sparing him and keeping him as your loyal seamster.", warn:"Do NOT give Boc the Larval Tear he asks for - it kills him permanently. Only the 'You're Beautiful' Prattling Pate saves him.", kind:"npc", master:"M00", px:4457.8, py:3404.6 },
  ]},
  { id:"roderika", name:"Roderika", color:"#d98ab0", steps:[
    { n:1, title:"Meet Roderika at Stormhill Shack", desc:"Find the frightened Roderika inside Stormhill Shack and exhaust her dialogue to learn she is searching for her lost comrades.", warn:"", kind:"grace", master:"M00", px:3472.8, py:6767 },
    { n:2, title:"Receive the Sitting Sideways gesture", desc:"Continue speaking with Roderika until she shares her grief and grants you the Sitting Sideways gesture.", warn:"", kind:"npc", master:"M00", px:2846.6, py:7616.9 },
    { n:3, title:"Receive the Spirit Jellyfish Ashes and quest", desc:"Speak to Roderika once more so she hands over the Spirit Jellyfish Ashes and asks you to seek the fate of her Chrysalids.", warn:"", kind:"npc", master:"M00", px:2846.6, py:7616.9 },
    { n:4, title:"Retrieve the Chrysalids' Memento", desc:"Pick up the Chrysalids' Memento from the pile of corpses near the Rampart Tower in Stormveil Castle.", warn:"Grab this before resting at any Liurnia grace or beating Godrick - either moves Roderika to the Hold and locks out her Golden Seed.", kind:"item", master:"M00", px:3127.6, py:6713.1 },
    { n:5, title:"Deliver the Memento to Roderika", desc:"Return to Stormhill Shack and show Roderika the Chrysalids' Memento, prompting her to lament the Chrysalids' fate and relocate to the Roundtable Hold.", warn:"Deliver before she relocates. If she moves to the Hold via a Liurnia grace or beating Godrick first, the Golden Seed is lost for good.", kind:"npc", master:"M00", px:2846.6, py:7616.9 },
    { n:6, title:"Find Roderika at Roundtable Hold", desc:"Travel to the Roundtable Hold and speak with the relocated Roderika by the fireplace, who rewards you with a Golden Seed.", warn:"", kind:"grace", master:"M00", px:2841.2, py:7610 },
    { n:7, title:"Ask Hewg about Roderika", desc:"Speak to Smithing Master Hewg in the Roundtable Hold and ask about Roderika to learn she has a gift for spirit tuning.", warn:"", kind:"npc", master:"M00", px:2877.3, py:7615.6 },
    { n:8, title:"Tell Roderika what Hewg said", desc:"Return to Roderika and relay Hewg's words, encouraging her to pursue her latent talent.", warn:"", kind:"npc", master:"M00", px:2846.6, py:7616.9 },
    { n:9, title:"Convince Hewg to teach her", desc:"Speak to Hewg once more to convince him that Roderika wishes to learn, then rest and fast travel so she relocates to his smithing room.", warn:"", kind:"npc", master:"M00", px:2877.3, py:7615.6 },
    { n:10, title:"Roderika becomes the Spirit Tuner", desc:"Speak to Roderika, Spirit Tuner beside Hewg, where she can now upgrade your Spirit Ashes using Grave and Ghost Glovewort.", warn:"", kind:"npc", master:"M00", px:2865.6, py:7612.9 },
    { n:11, title:"Receive the Curtsy gesture", desc:"After upgrading any Spirit Ash to +4, speak with Roderika again to hear of her newfound confidence and receive the Curtsy gesture.", warn:"", kind:"npc", master:"M00", px:2865.6, py:7612.9 },
  ]},
  { id:"dquest", name:"D, Hunter of the Dead", color:"#c9c9c9", steps:[
    { n:1, title:"Meet D in Limgrave", desc:"Find D, Hunter of the Dead mourning a corpse just east of Stormhill Shack, where he warns that the nearby Summonwater Village has been touched by Death.", warn:"D can ONLY be killed here in Limgrave. Once he moves to Roundtable Hold, killing him for the early Twinned Set is impossible forever.", kind:"npc", master:"M00", px:4229.2, py:6510 },
    { n:2, title:"Clear Summonwater Village", desc:"Travel to Summonwater Village and defeat the Tibia Mariner who is raising Those Who Live in Death.", warn:"", kind:"boss", master:"M00", px:4445, py:6526.7 },
    { n:3, title:"Speak with D after the hunt", desc:"Return to the southwestern entrance of Summonwater Village to hear D commend your slaying of the deathly horde.", warn:"", kind:"npc", master:"M00", px:4402.3, py:6541.1 },
    { n:4, title:"Reunite with D at Roundtable Hold", desc:"Rest at the Roundtable Hold and find D, where he explains his crusade against Those Who Live in Death.", warn:"", kind:"npc", master:"M00", px:2843.5, py:7605.9 },
    { n:5, title:"Show D a Deathroot", desc:"Present any Deathroot to D at the Roundtable Hold so he directs you to Gurranq at the Bestial Sanctum.", warn:"", kind:"npc", master:"M00", px:2843.5, py:7605.9 },
    { n:6, title:"Deliver Deathroot to Gurranq", desc:"Take the sending gate to the Bestial Sanctum and feed Deathroot to Gurranq, the Beast Clergyman, for his rewards.", warn:"", kind:"npc", master:"M00", px:5943.5, py:5473.6 },
    { n:7, title:"Accept the Weathered Dagger from Fia", desc:"During Fia's questline at the Roundtable Hold, accept the Weathered Dagger she asks you to return to its owner.", warn:"", kind:"npc", master:"M00", px:2880.7, py:7627.1 },
    { n:8, title:"Give the Weathered Dagger to D", desc:"Hand the Weathered Dagger to D at the Roundtable Hold, who recognizes its owner and promises to return it.", warn:"Hand over the Weathered Dagger BEFORE reaching Crumbling Farum Azula. Arriving there auto-kills D and locks the dagger hand-off.", kind:"npc", master:"M00", px:2843.5, py:7605.9 },
    { n:9, title:"Discover D slain by Fia", desc:"After advancing Fia's quest and reloading, find D's corpse in a newly opened room behind Smithing Master Hewg, slain by Fia for hunting Those Who Live in Death.", warn:"", kind:"npc", master:"M00", px:2843.5, py:7605.9 },
    { n:10, title:"Loot the Twinned Set and Bell Bearing", desc:"Collect the unaltered Twinned Set and D's Bell Bearing from his body in the newly opened room at the Roundtable Hold.", warn:"", kind:"item", master:"M00", px:2841.2, py:7610 },
    { n:11, title:"Reach Nokron, Eternal City", desc:"Progress Ranni's quest to defeat Starscourge Radahn and descend into Nokron, the Eternal City revealed by the falling star.", warn:"", kind:"boss", master:"M00", px:6228.5, py:6825.9 },
    { n:12, title:"Find D's twin brother in Nokron", desc:"Travel through the Siofra Aqueduct to find D's brother Devin just outside the Valiant Gargoyles arena, who teaches the Inner Order gesture on interaction.", warn:"", kind:"npc", master:"M01", px:5182.1, py:6344.8 },
    { n:13, title:"Give the unaltered Twinned armor to the brother", desc:"Hand over the complete, unaltered Twinned Set to Devin outside the Valiant Gargoyles arena so he dons it to avenge D.", warn:"The full Twinned Set must be UNALTERED in your inventory. If any piece is altered, Devin refuses it and the Inseparable Sword path is blocked.  Â·  Giving Devin the armor ends Fia's questline with her death; if Fia is unavailable you can't reclaim the Twinned Set until much later progression.", kind:"npc", master:"M01", px:5182.1, py:6344.8 },
    { n:14, title:"Confront the brother over Fia's body", desc:"After defeating Lichdragon Fortissax in Fia's dream and obtaining the Mending Rune of the Death-Prince, find D's armored brother standing over the slain Fia in Deeproot Depths.", warn:"", kind:"npc", master:"M01", px:4469.6, py:3109.5 },
    { n:15, title:"Claim the Inseparable Sword", desc:"Rest at the grace so the brother departs, then take the Inseparable Sword he leaves beside Fia's body in Deeproot Depths.", warn:"", kind:"item", master:"M01", px:4469.6, py:3109.5 },
  ]},
  { id:"kenneth", name:"Kenneth Haight", color:"#cbb12b", steps:[
    { n:1, title:"Meet Kenneth on the highway", desc:"Find Kenneth Haight shouting atop a ruined archway in northeastern Limgrave just northeast of the Mistwood Outskirts grace, where he asks you to retake Fort Haight.", warn:"", kind:"npc", master:"M00", px:4391.4, py:6813.2 },
    { n:2, title:"Clear Fort Haight's battlements", desc:"Travel to Fort Haight southeast of the Mistwood Ruins and defeat the Godrick Knight on the ramparts, who drops the Ash of War: Bloody Slash.", warn:"", kind:"grace", master:"M00", px:4596.3, py:7340.7 },
    { n:3, title:"Report back and claim your reward", desc:"Return to Kenneth at the archway, where he rewards you with the Erdsteel Dagger and offers to take you into his service.", warn:"", kind:"npc", master:"M00", px:4391.4, py:6813.2 },
    { n:4, title:"Obtain the Erdsteel Dagger", desc:"Receive the Erdsteel Dagger from Kenneth as your reward for retaking the fort.", warn:"", kind:"item", master:"M00", px:4222.9, py:3466.9 },
    { n:5, title:"Find Kenneth occupying Fort Haight", desc:"After resting at a grace, find Kenneth relocated to the now Demi-Human-infested Fort Haight, where he says he must find Limgrave's true heir before knighting you.", warn:"", kind:"grace", master:"M00", px:4596.3, py:7340.7 },
    { n:6, title:"Give Nepheli the Stormhawk King", desc:"Advance Nepheli Loux's quest by giving her the Stormhawk King while never giving her Seluvis's Potion, keeping her on the path to rule Limgrave.", warn:"Give Nepheli the Stormhawk King at Roundtable Hold BEFORE defeating Maliketh. Beat Maliketh first and she leaves; quest can't be finished.  Â·  Never give Nepheli Seluvis's Potion. It turns her into a puppet, permanently ending her quest and Kenneth's conclusion.  Â·  Defeating Morgott moves Nepheli out of Roundtable Hold, so give her the Stormhawk King before that boss fight.", kind:"npc", master:"M00", px:2855.1, py:7582.6 },
    { n:7, title:"Defeat Morgott to open Stormveil's resolution", desc:"Defeat Morgott, the Omen King atop Leyndell so that Nepheli's questline and Kenneth's conclusion can progress.", warn:"", kind:"boss", master:"M00", px:4564.4, py:3776.2 },
    { n:8, title:"Trigger the Stormveil conclusion", desc:"Rest at the Godrick the Grafted site of grace in Stormveil Castle to gather Kenneth and Nepheli in the throne room.", warn:"", kind:"grace", master:"M00", px:3099.5, py:6462.7 },
    { n:9, title:"Hear Nepheli named ruler of Limgrave", desc:"Speak to Kenneth in Stormveil's throne room, where he declares Nepheli Loux the new ruler of Limgrave, completing his quest.", warn:"", kind:"npc", master:"M00", px:3047.1, py:6399.8 },
  ]},
  { id:"rya", name:"Rya and Zorayas", color:"#9b6dd1", steps:[
    { n:1, title:"Meet Rya in Liurnia", desc:"Speak with Rya the Scout at the pavilion by the Birdseye Telescope between the Laskyar Ruins and Boilprawn Shack in Liurnia of the Lakes, where she asks you to recover her stolen necklace.", warn:"Talk to Rya here BEFORE entering Volcano Manor. Joining the Manor first permanently locks out Blackguard Big Boggart (Boiled Prawn/Crab).", kind:"npc", master:"M00", px:2481.4, py:5716.2 },
    { n:2, title:"Find Blackguard Big Boggart", desc:"Travel north to the Boilprawn Shack and find the ruffian who took the necklace, who offers to sell you Rya's Necklace for 1,000 runes (or drops it if killed).", warn:"Don't kill Boggart early - doing so locks out his shop (Boiled Crab) and questline. Buying the necklace is the safe route.", kind:"grace", master:"M00", px:2257.7, py:5564.1 },
    { n:3, title:"Buy Rya's Necklace", desc:"Choose \"Give me the necklace\" and purchase Rya's Necklace from Blackguard Big Boggart at the Boilprawn Shack for 1,000 runes to recover Rya's stolen pendant.", warn:"", kind:"item", master:"M00", px:2261.7, py:5561.0 },
    { n:4, title:"Return the necklace to Rya", desc:"Bring the necklace back to Rya the Scout at her Liurnia pavilion, and she rewards you with an Invitation to Volcano Manor and asks you to meet her on the Altus Plateau.", warn:"", kind:"npc", master:"M00", px:2481.4, py:5716.2 },
    { n:5, title:"Obtain the Volcano Manor Invitation", desc:"Receive the Volcano Manor Invitation from Rya, the letter of recruitment that grants you entry into the Recusants of Volcano Manor.", warn:"", kind:"item", master:"M00", px:2608, py:5941 },
    { n:6, title:"Meet Rya on the Altus Plateau", desc:"Find Rya the Scout at the top of the Grand Lift of Dectus (or at the lower Lux Ruins above Erdtree-Gazing Hill if you took the Ruin-Strewn Precipice route), where she teleports you directly into Volcano Manor.", warn:"", kind:"npc", master:"M00", px:2754.4, py:3716.7 },
    { n:7, title:"Speak to Rya in the drawing room", desc:"Inside Volcano Manor, talk with Rya in the drawing room near the Volcano Manor Site of Grace, where she gives you your first assassination contract.", warn:"Don't blitz all of Tanith's contracts at once; rushing them skips Rya's quest beats and her serpent-room dialogue.", kind:"npc", master:"M00", px:2206.6, py:2918.6 },
    { n:8, title:"Complete the first assassination contract", desc:"Travel to the bridge near Warmaster's Shack in Limgrave and invade and defeat Old Knight Istvan to fulfill Volcano Manor's first contract.", warn:"", kind:"npc", master:"M00", px:3652.9, py:6420 },
    { n:9, title:"Discover Zorayas's true form", desc:"Return to Volcano Manor, rest, and enter the now-unlocked room across the corridor from the drawing room to find Rya in serpent form, where she reveals her real name, Zorayas.", warn:"", kind:"npc", master:"M00", px:2189.4, py:2895.2 },
    { n:10, title:"Defeat the Godskin Noble", desc:"Progress through Volcano Manor and slay the Godskin Noble in the Temple of Eiglay to gain access to the Serpent's Amnion.", warn:"", kind:"boss", master:"M00", px:2250.3, py:3045.5 },
    { n:11, title:"Collect the Serpent's Amnion", desc:"Take the Serpent's Amnion from the altar at the back of the Temple of Eiglay after the Godskin Noble is defeated.", warn:"", kind:"item", master:"M00", px:2254.9, py:3047.3 },
    { n:12, title:"Give the Serpent's Amnion to Zorayas", desc:"Bring the Serpent's Amnion to Zorayas in the locked room across from the drawing room, where she despairs over her grotesque serpent origins.", warn:"Speak to Zorayas in her room and resolve her fate BEFORE killing Rykard. Beating Rykard first makes her vanish, leaving no reward.", kind:"npc", master:"M00", px:2189.4, py:2895.2 },
    { n:13, title:"Decide Zorayas's fate", desc:"Choose to kill her, give her the Tonic of Forgetfulness (received from Tanith) so she returns to the manor remembering nothing, or refuse both and leave her to make peace with her nature.", warn:"The Tonic of Forgetfulness ending needs the Tonic from Tanith first. Finishing all contracts/Rykard before getting it can lock out that choice.", kind:"npc", master:"M00", px:2189.4, py:2895.2 },
    { n:14, title:"Claim Daedicar's Woe", desc:"However you resolve her fate, defeat Rykard and return to obtain the Daedicar's Woe talisman (with Zorayas's Letter as well if you spared her without the tonic), a cursed talisman that increases the damage you take.", warn:"Reward only drops if you spoke to Zorayas in her dungeon room pre-Rykard. Defeating Rykard beforehand forfeits Daedicar's Woe and her Letter.", kind:"item", master:"M00", px:2194.2, py:2970.9 },
  ]},
  { id:"seluvis", name:"Preceptor Seluvis", color:"#7a5bd6", steps:[
    { n:1, title:"Reach the Three Sisters", desc:"Defeat Royal Knight Loretta in Caria Manor and proceed into the Three Sisters area of northwest Liurnia.", warn:"", kind:"grace", master:"M00", px:1578.7, py:3698.2 },
    { n:2, title:"Begin Ranni's quest", desc:"Enter Ranni's Rise and speak with Ranni the Witch to join her service, which introduces the projections of Iji, Blaidd, and Seluvis.", warn:"", kind:"npc", master:"M00", px:1611.3, py:3686.4 },
    { n:3, title:"Meet Seluvis's spectral form", desc:"After speaking with Ranni, talk to the spectral image of Preceptor Seluvis on the ground floor of Ranni's Rise, who asks you to visit him in person.", warn:"", kind:"npc", master:"M00", px:1608.8, py:3682.6 },
    { n:4, title:"Visit Seluvis's Rise", desc:"Go to Seluvis's Rise, the southernmost tower of the Three Sisters, and speak with Preceptor Seluvis to receive the potion task.", warn:"", kind:"npc", master:"M00", px:1608.8, py:3682.6 },
    { n:5, title:"Receive Seluvis's Potion", desc:"Accept Seluvis's Potion, which he tasks you with secretly administering to Nepheli Loux.", warn:"", kind:"item", master:"M00", px:1578.7, py:3698.2 },
    { n:6, title:"Give the potion to Nepheli Loux", desc:"After defeating the Omenkiller in the Village of the Albinaurics and speaking to Gideon about Nepheli's Despair, give Seluvis's Potion to Nepheli Loux, Warrior at the Roundtable Hold so she is turned into a puppet.", warn:"Only puppetizing Nepheli here yields the Nepheli Loux Puppet later. Giving the potion to Gideon or Dung Eater instead loses it permanently.", kind:"npc", master:"M00", px:2855.1, py:7582.6 },
    { n:7, title:"Find the hidden puppet workshop", desc:"Strike the illusory floor of the ruins between Ranni's Rise and Renna's Rise to reveal Seluvis's secret laboratory full of puppets.", warn:"", kind:"grace", master:"M00", px:1578.7, py:3698.2 },
    { n:8, title:"Confront Seluvis and claim a free puppet", desc:"Return to Seluvis, select the chambers dialogue to confront him, and receive one free puppet Spirit Ash (Finger Maiden Therolina Puppet or Jarwight Puppet).", warn:"", kind:"npc", master:"M00", px:1608.8, py:3682.6 },
    { n:9, title:"Buy a Weathered Map from Pidia", desc:"Follow the clifftop above Caria Manor southwest to reach Pidia, Carian Servant and purchase the Weathered Map revealing the amber light's location.", warn:"Buy the Weathered Map and any wanted puppets from Pidia before step 14; giving Ranni the Fingerslayer Blade kills both Seluvis and Pidia.", kind:"npc", master:"M00", px:1812.3, py:3733.7 },
    { n:10, title:"Obtain the Amber Starlight", desc:"Travel to the ravine northeast of the Altus Highway Junction and pick up the Amber Starlight in front of the statue.", warn:"", kind:"item", master:"M00", px:3199.2, py:3256.8 },
    { n:11, title:"Deliver the Amber Starlight to Seluvis", desc:"Bring the Amber Starlight back to Preceptor Seluvis at Seluvis's Rise.", warn:"", kind:"npc", master:"M00", px:1608.8, py:3682.6 },
    { n:12, title:"Receive the Magic Scorpion Charm", desc:"Seluvis rewards you with the Magic Scorpion Charm talisman for delivering the Amber Starlight.", warn:"Deliver the Amber Starlight and claim the Magic Scorpion Charm before giving Ranni the Fingerslayer Blade (step 14), which kills Seluvis and locks this reward.", kind:"item", master:"M00", px:1578.7, py:3698.2 },
    { n:13, title:"Receive the Amber Draught (optional betrayal)", desc:"Speak with Seluvis again to receive the Amber Draught he wants administered to Ranni; do NOT give it to her unless you intend to betray and lock out her quest.", warn:"Giving Ranni the Amber Draught locks her quest (recover only via Church of Vows absolution). Giving the Fingerslayer Blade first removes this betrayal option entirely.", kind:"item", master:"M00", px:1578.7, py:3698.2 },
    { n:14, title:"Advance Ranni's quest to its trigger", desc:"Continue Ranni's questline and obtain the Fingerslayer Blade from the chest in Nokron, Eternal City, ignoring Seluvis's request to poison Ranni.", warn:"", kind:"item", master:"M01", px:4873.2, py:6759.4 },
    { n:15, title:"Give the Fingerslayer Blade to Ranni", desc:"Hand the Fingerslayer Blade to Ranni the Witch, which advances her quest and triggers Seluvis's death.", warn:"", kind:"npc", master:"M00", px:1611.3, py:3686.4 },
    { n:16, title:"Loot Seluvis's corpse", desc:"Find Preceptor Seluvis dead at Seluvis's Rise and take the Preceptor's armor set and Seluvis's Bell Bearing, buying any remaining puppets from his body.", warn:"", kind:"npc", master:"M00", px:1608.8, py:3682.6 },
    { n:17, title:"Claim the Nepheli Loux Puppet from Pidia", desc:"Return to Caria Manor where Pidia, Carian Servant now lies dead, slain by his own puppets, and collect Pidia's Bell Bearing and the Nepheli Loux Puppet.", warn:"Pidia only dies and drops the Nepheli Loux Puppet if you turned Nepheli into a puppet in step 5; otherwise this reward is unobtainable.", kind:"npc", master:"M00", px:1812.3, py:3733.7 },
  ]},
  { id:"thiollier", name:"Thiollier", color:"#6a6f8c", steps:[
    { n:1, title:"Meet Thiollier at Pillar Path Cross", desc:"Speak with Thiollier where he kneels in mourning at the Pillar Path Cross Site of Grace in Scadu Altus, east of Castle Ensis, and exhaust his dialogue about St. Trina to unlock his shop.", warn:"", kind:"npc", master:"M10", px:5288.2, py:5584.5 },
    { n:2, title:"Buy poison wares from Thiollier", desc:"Purchase his poison-related stock, including Trina's Lily and the Deadly Poison Perfume Bottle, while he is still stationed at Pillar Path Cross.", warn:"Buy his wares (Deadly Poison Perfume Bottle, Trina's Lily) now. He leaves Pillar Path Cross once Miquella's Great Rune breaks and the shop is gone.", kind:"npc", master:"M10", px:5288.2, py:5584.5 },
    { n:3, title:"Receive Black Syrup from Moore", desc:"Speak with Moore at the Main Gate Cross near Belurat to receive the Black Syrup item needed for the optional Thiollier exchange.", warn:"", kind:"npc", master:"M10", px:4377.7, py:5666.1 },
    { n:4, title:"Give Black Syrup to Thiollier for his Concoction", desc:"Hand the Black Syrup to Thiollier at Pillar Path Cross to receive Thiollier's Concoction in return, which feeds into the Dragon Communion Priestess quest; this is part of Moore's intended quest and does not break it.", warn:"Get Black Syrup from Moore and give it to Thiollier before he departs Pillar Path Cross, or the Concoction exchange is lost permanently.", kind:"npc", master:"M10", px:5288.2, py:5584.5 },
    { n:5, title:"Break Miquella's Great Rune", desc:"Defeat Messmer and Romina and approach Shadow Keep until the message \"Somewhere, a great rune has broken\" appears, advancing Thiollier's quest.", warn:"", kind:"grace", master:"M10", px:5381.4, py:4264 },
    { n:6, title:"Speak to Thiollier after the rune breaks", desc:"Return to Thiollier at Pillar Path Cross for his updated dialogue, reloading the area if he says he has something to tell you, then finish buying his wares before he departs.", warn:"", kind:"npc", master:"M10", px:5288.2, py:5584.5 },
    { n:7, title:"Descend Stone Coffin Fissure", desc:"Enter the Stone Coffin Fissure from the southern tip of the Cerulean Coast and drop down through its ledges toward the depths.", warn:"", kind:"grace", master:"M10", px:5106.1, py:7427.4 },
    { n:8, title:"Defeat the Putrescent Knight", desc:"Beat the Putrescent Knight at the bottom of the Stone Coffin Fissure to open the path to St. Trina.", warn:"", kind:"boss", master:"M10", px:5433.9, py:7335.7 },
    { n:9, title:"Find St. Trina at Garden of Deep Purple", desc:"Rest at the Garden of Deep Purple Site of Grace and approach the sleeping St. Trina amid the purple flowers at the end of the cave.", warn:"", kind:"npc", master:"M10", px:5324.6, py:7360.6 },
    { n:10, title:"Tell Thiollier of St. Trina's location", desc:"Return to Thiollier at Pillar Path Cross and choose to reveal St. Trina's whereabouts, sending him to her side.", warn:"", kind:"npc", master:"M10", px:5288.2, py:5584.5 },
    { n:11, title:"Speak to Thiollier beside St. Trina", desc:"Travel to the Garden of Deep Purple to find Thiollier now kneeling before St. Trina and exhaust his dialogue.", warn:"", kind:"npc", master:"M10", px:5332.2, py:7366.9 },
    { n:12, title:"Imbibe St. Trina's nectar repeatedly", desc:"Choose to imbibe St. Trina's nectar at the Garden of Deep Purple, dying and respawning each time, until St. Trina speaks to you on the death screen after about four imbibes.", warn:"", kind:"npc", master:"M10", px:5324.6, py:7360.6 },
    { n:13, title:"Pass St. Trina's words to Thiollier", desc:"Speak again to Thiollier at the Garden of Deep Purple to relay St. Trina's message, which he angrily refuses to believe.", warn:"", kind:"npc", master:"M10", px:5332.2, py:7366.9 },
    { n:14, title:"Survive Thiollier's invasion", desc:"Rest or imbibe the nectar once more to be invaded by Thiollier at the Garden of Deep Purple, then defeat him to make him withdraw.", warn:"Defeat his Garden of Deep Purple invasion BEFORE the Enir-Ilim NPC fight, or he vanishes from the cave and his quest ends early.", kind:"npc", master:"M10", px:5332.2, py:7366.9 },
    { n:15, title:"Obtain St. Trina's Smile", desc:"Collect the St. Trina's Smile talisman granted after defeating Thiollier in his invasion.", warn:"", kind:"item", master:"M10", px:5388.8, py:7369.2 },
    { n:16, title:"Burn the Sealing Tree at Church of the Bud", desc:"Burn the Sealing Tree at the Church of the Bud to advance the main story, the point of no return for Thiollier's questline.", warn:"Burning the Sealing Tree halts all of Miquella's followers' quests. Finish Thiollier's invasion and reconciliation steps first.", kind:"grace", master:"M10", px:4167.6, py:4867.8 },
    { n:17, title:"Speak to the reconciled Thiollier", desc:"Return to the Garden of Deep Purple to find Thiollier now calmed at St. Trina's side and exhaust his final dialogue.", warn:"", kind:"npc", master:"M10", px:5332.2, py:7366.9 },
    { n:18, title:"Summon Thiollier against Leda's band", desc:"Use Thiollier's golden summon sign before the gauntlet fight against Needle Knight Leda and her allies at Enir-Ilim.", warn:"You must summon him for the Leda band fight to make him summonable at the final boss; skipping it locks that out (his gear still drops).", kind:"npc", master:"M10", px:4133.6, py:5399.7 },
    { n:19, title:"Summon Thiollier for the final boss", desc:"Summon Thiollier with his golden sign before Radahn, Consort of Miquella, to fight alongside him at the climax.", warn:"", kind:"boss", master:"M10", px:4064.8, py:5211.2 },
    { n:20, title:"Claim Thiollier's gear", desc:"After the final fight, collect Thiollier's Hidden Needle and his full armor set of Mask, Garb, Gloves, and Trousers.", warn:"", kind:"item", master:"M01", px:2709.4, py:4235.2 },
  ]},
  { id:"ymir", name:"Count Ymir, High Priest", color:"#a05fd6", steps:[
    { n:1, title:"Reach Scadu Altus", desc:"Defeat Rellana, Twin Moon Knight at Castle Ensis to open the path into Scadu Altus, where the Cathedral of Manus Metyr stands.", warn:"", kind:"boss", master:"M10", px:5192.5, py:5197.4 },
    { n:2, title:"Meet Count Ymir", desc:"Speak with and fully exhaust Count Ymir's dialogue on his throne in the Cathedral of Manus Metyr to begin his quest and receive the Hole-Laden Necklace and the first Ruins Map.", warn:"", kind:"npc", master:"M10", px:5852.8, py:4966.5 },
    { n:3, title:"Note Jolan at the cathedral", desc:"Observe Swordhand of Night Jolan leaning against a pillar in the Cathedral of Manus Metyr, who stays silent until Ymir's quest progresses.", warn:"", kind:"npc", master:"M10", px:5913.5, py:4979.1 },
    { n:4, title:"Ring the bell at Finger Ruins of Rhia", desc:"Travel east along the beach from Cerulean Coast Cross to the Finger Ruins of Rhia and sound the bell among the circle of finger statues to earn the Crimson Seed Talisman +1.", warn:"", kind:"grace", master:"M10", px:5754.6, py:6732.7 },
    { n:5, title:"Report the first bell to Ymir", desc:"Return to Count Ymir in the Cathedral of Manus Metyr to receive the Beloved Stardust talisman, the second Ruins Map, and new purchasable sorceries.", warn:"", kind:"npc", master:"M10", px:5852.8, py:4966.5 },
    { n:6, title:"Ring the bell at Finger Ruins of Dheo", desc:"Reach Scaduview via the Storeroom, Back Section in Shadow Keep, use the O Mother gesture at the altar to open the path, then sound the bell at the Finger Ruins of Dheo to obtain the Cerulean Seed Talisman +1.", warn:"", kind:"grace", master:"M10", px:5852.8, py:4966.5 },
    { n:7, title:"Report the second bell to Ymir", desc:"Speak again with Count Ymir in the Cathedral of Manus Metyr to receive the third Ruins Map for the Finger Ruins of Miyr.", warn:"", kind:"npc", master:"M10", px:5852.8, py:4966.5 },
    { n:8, title:"Open the throne path to Miyr", desc:"Rest at the Cathedral of Manus Metyr grace, then examine Count Ymir's throne to reveal the hidden passage leading down into the Finger Ruins of Miyr.", warn:"", kind:"grace", master:"M10", px:5852.8, py:4966.5 },
    { n:9, title:"Defeat the invader Anna", desc:"While crossing the Finger Ruins of Miyr, defeat the invading Swordhand of Night Anna to obtain the Claws of Night.", warn:"", kind:"grace", master:"M10", px:5852.8, py:4966.5 },
    { n:10, title:"Blow the horn at Miyr", desc:"Continue through the Finger Ruins of Miyr and sound the horn at the end of the passage to be teleported to Metyr, Mother of Fingers.", warn:"", kind:"grace", master:"M10", px:5852.8, py:4966.5 },
    { n:11, title:"Defeat Metyr, Mother of Fingers", desc:"Slay Metyr, Mother of Fingers to earn the Remembrance of the Mother of Fingers, which Enia can trade for the Staff of the Great Beyond or Gazing Finger.", warn:"", kind:"boss", master:"M10", px:5508.3, py:3970.3 },
    { n:12, title:"Defeat the hostile Count Ymir", desc:"Return to the Cathedral of Manus Metyr where Ymir turns hostile, and defeat Count Ymir, Mother of Fingers to claim the Maternal Staff, the High Priest armor set, and Ymir's Bell Bearing.", warn:"", kind:"npc", master:"M10", px:5921.1, py:4998.6 },
    { n:13, title:"Collect Cherishing Fingers", desc:"Pick up the Cherishing Fingers sorcery from Ymir's grave in the small graveyard just west of the Cathedral of Manus Metyr after his defeat.", warn:"", kind:"item", master:"M01", px:2709.4, py:4235.2 },
    { n:14, title:"Speak to grieving Jolan", desc:"Rest and return to find Swordhand of Night Jolan slumped at her pillar in the Cathedral of Manus Metyr, where she asks for an Iris of Grace or an Iris of Occultation.", warn:"", kind:"npc", master:"M10", px:5913.5, py:4979.1 },
    { n:15, title:"Acquire an Iris", desc:"Obtain either the Iris of Grace or the Iris of Occultation to bring back to Jolan, since her finale reward depends on which one you give.", warn:"", kind:"item", master:"M10", px:5913.5, py:4979.1 },
    { n:16, title:"Give the Iris to Jolan", desc:"Hand Swordhand of Night Jolan the Iris of Occultation to receive the Sword of Night and end her quest, or the Iris of Grace to receive the Swordhand of Night Jolan spirit ashes.", warn:"Mutually exclusive: Iris of Occultation = Sword of Night (kills Jolan); Iris of Grace = Jolan spirit ashes. You get only one per playthrough.  Â·  Giving Iris of Occultation kills Jolan, permanently locking out her spirit ashes and the upgraded Jolan & Anna ashes. Pick Iris of Grace to keep that path.", kind:"npc", master:"M10", px:5913.5, py:4979.1 },
  ]},
  { id:"ansbach", name:"Sir Ansbach", color:"#8b1a1a", steps:[
    { n:1, title:"Meet Sir Ansbach at Main Gate Cross", desc:"Speak with Sir Ansbach where he rests beside Miquella's cross at the Main Gate Cross grace and exhaust his dialogue about Mohg and the crosses.", warn:"", kind:"npc", master:"M10", px:4384.2, py:5667.6 },
    { n:2, title:"Report Miquella's crosses (optional)", desc:"Optionally find more of Miquella's crosses and return to Sir Ansbach at Main Gate Cross for extra lore dialogue.", warn:"", kind:"npc", master:"M10", px:4384.2, py:5667.6 },
    { n:3, title:"Approach Shadow Keep to relocate Ansbach", desc:"Advance into Scadu Altus and approach Shadow Keep so Miquella's great rune breaks, then speak with Sir Ansbach and rest so he leaves Main Gate Cross and relocates inside the Storehouse. Rellana, Twin Moon Knight is an optional boss on the route, not a requirement.", warn:"", kind:"boss", master:"M10", px:5192.5, py:5197.4 },
    { n:4, title:"Find Ansbach in the Storehouse", desc:"Enter Shadow Keep's Specimen Storehouse and find Sir Ansbach in a room north of the Storehouse, First Floor grace.", warn:"", kind:"npc", master:"M10", px:5534.6, py:4312 },
    { n:5, title:"Meet Redmane Freyja in the Storehouse", desc:"Climb to the Storehouse, Seventh Floor grace and exhaust Redmane Freyja's dialogue so you learn of her decision before involving Ansbach.", warn:"Must hear Freyja's decision here BEFORE handing Ansbach the Secret Rite Scroll, or he leaves first and the Letter/Golden Lion Shield is lost.", kind:"npc", master:"M10", px:5473.1, py:4339.1 },
    { n:6, title:"Collect the Secret Rite Scroll", desc:"Retrieve the Secret Rite Scroll from a table behind tall bookshelves reached from the Storehouse, Fourth Floor grace.", warn:"", kind:"item", master:"M10", px:5466.1, py:4360.7 },
    { n:7, title:"Tell Ansbach about Freyja and give the Secret Rite Scroll", desc:"Return to Sir Ansbach at the Storehouse, First Floor, tell him of Freyja's decision, then hand over the Secret Rite Scroll, prompting his conclusion that Miquella means to use Mohg's body as Radahn's vessel.", warn:"Talk to Freyja (step 5) first. Give the scroll before that and Ansbach departs, locking out the Letter for Freyja and Golden Lion Shield.", kind:"npc", master:"M10", px:5534.6, py:4312 },
    { n:8, title:"Receive the Letter for Freyja", desc:"Rest at a grace and speak with Sir Ansbach again at the Storehouse, First Floor so he entrusts you with the Letter for Freyja.", warn:"", kind:"npc", master:"M10", px:5534.6, py:4312 },
    { n:9, title:"Deliver the letter to Freyja", desc:"Take the Letter for Freyja to Redmane Freyja at the Storehouse, Seventh Floor and give it to her, receiving the Golden Lion Shield in return.", warn:"", kind:"npc", master:"M10", px:5473.1, py:4339.1 },
    { n:10, title:"Return Freyja's reply to Ansbach", desc:"Report back to Sir Ansbach at the Storehouse, First Floor to relay Freyja's response and advance his quest.", warn:"", kind:"npc", master:"M10", px:5534.6, py:4312 },
    { n:11, title:"Exhaust Needle Knight Leda's dialogue", desc:"Speak with Needle Knight Leda at the Highroad Cross grace until she turns on her companions and triggers the Storehouse confrontation.", warn:"", kind:"npc", master:"M10", px:5185.7, py:5233.9 },
    { n:12, title:"Side with Ansbach against Leda", desc:"Return to Sir Ansbach's room at the Storehouse, First Floor and touch the gold summon sign to fight on his side against Needle Knight Leda, earning Ansbach's Longbow and Leda's Rune.", warn:"Touch the GOLD sign only. The red sign (helping Leda) permanently kills Ansbach and ends his quest and later summons.", kind:"boss", master:"M10", px:4130.4, py:5398.8 },
    { n:13, title:"Burn the Sealing Tree (point of no return)", desc:"Progress the main story and burn the Sealing Tree at the Church of the Bud, after which the questline continues only in Enir-Ilim.", warn:"Finish all Ansbach steps through 12 first. Burning the Sealing Tree halts Miquella's followers' quests; it only continues in Enir-Ilim.", kind:"grace", master:"M10", px:4167.6, py:4867.8 },
    { n:14, title:"Summon Ansbach against the Band of Leda", desc:"In Enir-Ilim, use Sir Ansbach's gold summon sign at the Cleansing Chamber Anteroom ambush to help defeat Needle Knight Leda and her allies.", warn:"", kind:"boss", master:"M10", px:4130.4, py:5398.8 },
    { n:15, title:"Speak with Ansbach after the ambush", desc:"After the Band of Leda is defeated, talk to Sir Ansbach near the Cleansing Chamber Anteroom where he praises Thiollier and steels himself for what comes next.", warn:"", kind:"npc", master:"M10", px:4181.9, py:5334 },
    { n:16, title:"Summon Ansbach for the final boss", desc:"Use Sir Ansbach's gold summon sign before the Promised Consort Radahn fight to battle alongside him, completing his questline.", warn:"His gold sign must appear outside the boss room for rewards. He need not be summoned or die; an available sign guarantees his drops.", kind:"boss", master:"M10", px:4064.8, py:5211.2 },
    { n:17, title:"Collect Ansbach's rewards", desc:"If Sir Ansbach falls during the final battle, claim Ansbach's Set, the Obsidian Lamina scythe, and the Furious Blade of Ansbach incantation from his remains.", warn:"", kind:"item", master:"M10", px:4064.8, py:5211.2 },
  ]},
  { id:"moore", name:"Moore", color:"#6b8e23", steps:[
    { n:1, title:"Find Thiollier and open his shop", desc:"Travel to the Pillar Path Cross site of grace in Gravesite Plain and exhaust Thiollier's dialogue until his purchase menu becomes available.", warn:"", kind:"npc", master:"M10", px:5288.2, py:5584.5 },
    { n:2, title:"Meet Moore and buy from his shop", desc:"Find the melancholy merchant Moore seated with Sir Ansbach just outside Belurat at the Main Gate Cross site of grace and purchase any item to unlock his quest dialogue.", warn:"", kind:"npc", master:"M10", px:4377.7, py:5666.1 },
    { n:3, title:"Receive the Black Syrup from Moore", desc:"Select \"Talk to Moore\" to receive the Black Syrup, a black mournful liquor he asks you to deliver to his sorrowful friend Thiollier.", warn:"Get the Black Syrup BEFORE approaching Shadow Keep or starting Thiollier's St. Trina quest, or Moore won't hand it over this cycle.", kind:"item", master:"M10", px:4381.2, py:5659.5 },
    { n:4, title:"Deliver the Black Syrup to Thiollier", desc:"Return to Thiollier at Pillar Path Cross, give him the Black Syrup, then choose \"Ask about black syrup\" and \"I'm weary of life\" to obtain Thiollier's Concoction.", warn:"Deliver before Thiollier leaves for St. Trina and before Shadow Keep; if he relocates to Garden of Deep Purple the delivery is locked out permanently.", kind:"npc", master:"M10", px:5288.2, py:5584.5 },
    { n:5, title:"Obtain Forager Brood Cookbook (4)", desc:"Help the warming-stone pest at the forager brood north of the Church of the Crusade in Scadu Altus to receive Forager Brood Cookbook (4), which Moore's next gift depends on.", warn:"", kind:"item", master:"M10", px:5288.2, py:5584.5 },
    { n:6, title:"Collect Forager Brood Cookbook (7) from Moore", desc:"Return to Moore at Main Gate Cross to receive Forager Brood Cookbook (7), a reward that becomes permanently missable once his quest advances past this point.", warn:"Grab Cookbook (7) from Moore before the rune-break choice advances his quest; it becomes permanently inaccessible if he moves or dies.", kind:"item", master:"M10", px:4381.2, py:5659.5 },
    { n:7, title:"Break Miquella's Great Rune", desc:"Advance the main story by approaching Shadow Keep until the messages \"Somewhere, a great rune has been broken...\" and \"And so too has a powerful charm\" appear, unlocking Moore's final dialogue.", warn:"", kind:"npc", master:"M10", px:5241.2, py:5318.9 },
    { n:8, title:"Make the grim final choice", desc:"Speak with Moore again and answer \"Must we be sad together?\" by choosing \"Put it behind you,\" \"Remain sad forever,\" or \"I don't know,\" each deciding his fate.", warn:"Picking 'Put it behind you' or 'Remain sad forever' makes Moore leave, locking out any remaining Forager Brood cookbooks for this playthrough.", kind:"npc", master:"M10", px:5241.2, py:5318.9 },
    { n:9, title:"Resolve Moore's fate near Church of the Crusade", desc:"Depending on your choice, fight him among Leda's hostile group at Enir-Ilim, find his corpse on the cliffs north of Church of the Crusade, or face him there as a red phantom invader after he hunts the Forager Broods.", warn:"Finish Moore's quest before burning the Sealing Tree at Church of the Bud (after Romina) - that is the hard point of no return.", kind:"npc", master:"M10", px:5241.2, py:5318.9 },
    { n:10, title:"Claim the Verdigris set and Moore's Bell Bearing", desc:"However the quest ends, loot Moore's full Verdigris armor set, the Verdigris Greatshield, and Moore's Bell Bearing as his final legacy.", warn:"", kind:"item", master:"M10", px:5241.2, py:5318.9 },
  ]},
  { id:"igon", name:"Drake Warrior Igon", color:"#d9534f", steps:[
    { n:1, title:"Find the screaming Igon", desc:"From Castle Ensis head southeast to the Pillar Path Waypoint in eastern Gravesite Plain, where Drake Warrior Igon lies on the ground crying out in pain west of the grace.", warn:"", kind:"npc", master:"M10", px:6875.3, py:6456.5 },
    { n:2, title:"Exhaust Igon's early dialogue", desc:"Rest at the grace and talk to Igon repeatedly until he speaks of his vendetta against the dragon Bayle and only repeats lines about the exquisite pain.", warn:"", kind:"npc", master:"M10", px:6875.3, py:6456.5 },
    { n:3, title:"Descend into the Dragon's Pit", desc:"Take the marble-lined road south, defeat the red-named Ancient Dragon-Man invader, and work down through the Dragon's Pit dungeon toward its lower grace.", warn:"", kind:"grace", master:"M10", px:5176.7, py:6000.2 },
    { n:4, title:"Open the way to Jagged Peak", desc:"Drop down the abyss and defeat the Ancient Dragon-Man boss at the bottom of the pit to unlock the Dragon's Pit Terminus grace and the path onto the Jagged Peak.", warn:"", kind:"grace", master:"M10", px:5319.7, py:6064.3 },
    { n:5, title:"Commune at the Grand Altar", desc:"Take the right path from Dragon's Pit Terminus to the Grand Altar of Dragon Communion, speak with the Dragon Communion Priestess, and choose Devour draconic essence to receive the Ancient Dragon's Blessing.", warn:"", kind:"npc", master:"M10", px:5584.2, py:6623.1 },
    { n:6, title:"Clear the drakes at the peak's foot", desc:"Cross the bridge to the Foot of the Jagged Peak grace and slay the two feuding Jagged Peak Drakes, defeating the one with the boss health bar so Igon reappears nearby.", warn:"", kind:"grace", master:"M10", px:6088.7, py:6202.2 },
    { n:7, title:"Receive Igon's Furled Finger", desc:"Speak with Igon where he now sits amid the red smoke at the eastern canyon entrance until he gives you the Igon's Furled Finger so you can summon him against Bayle.", warn:"Must talk to Igon here after the Twin Drakes to get his Furled Finger - without it you cannot summon him for the Bayle fight.", kind:"item", master:"M10", px:6088.7, py:6202.2 },
    { n:8, title:"Obtain Thiollier's Concoction", desc:"Progress Thiollier's questline in the Shadow Keep / Church District area until he gives you Thiollier's Concoction, and do not drink it yourself.", warn:"Requires advancing Thiollier's quest (don't drink the concoction). It's needed for the Priestess/Florissax path before Bayle.", kind:"npc", master:"M10", px:5288.2, py:5584.5 },
    { n:9, title:"Put the Priestess to sleep at night", desc:"Rest until nightfall, then give Thiollier's Concoction to the Dragon Communion Priestess as she prays at the Grand Altar of Dragon Communion to make her fall asleep.", warn:"Give the concoction only at night, and do it before defeating Bayle - this choice is permanent.", kind:"npc", master:"M10", px:5584.2, py:6623.1 },
    { n:10, title:"Wait and exhaust her dreaming dialogue", desc:"Pass time across about two in-game days at the grace and speak with the Priestess until her dialogue about Florissax is fully exhausted, all before killing Bayle.", warn:"", kind:"npc", master:"M10", px:5584.2, py:6623.1 },
    { n:11, title:"Defeat Ancient Dragon Senessax", desc:"Head southeast and east from the Foot of the Jagged Peak past the spiritspring jumps and rolling boulders, then defeat Ancient Dragon Senessax blocking the ascent to the summit.", warn:"", kind:"grace", master:"M10", px:6088.7, py:6202.2 },
    { n:12, title:"Summon Igon and defeat Bayle", desc:"At the summit crater arena use Igon's golden summon sign just inside the fog wall and defeat Bayle the Dread with his aid across both phases.", warn:"Killing Bayle locks the Priestess outcome. Summon Igon and finish her concoction steps first or you forfeit Florissax rewards.", kind:"boss", master:"M10", px:6896, py:6502 },
    { n:13, title:"Claim the Dragonbolt of Florissax", desc:"Return to the Grand Altar of Dragon Communion and speak with the Priestess, who rewards you with the Dragonbolt of Florissax incantation in place of her usual rewards.", warn:"Only granted if you drugged the Priestess before Bayle. Otherwise she's dead and you get Flowerstone Gavel + Priestess Heart instead.", kind:"item", master:"M10", px:5596.3, py:6623.2 },
    { n:14, title:"Collect Igon's gear at the foot of the peak", desc:"Travel back to the Foot of the Jagged Peak where Igon has died of his wounds and collect his full equipment set including Igon's Greatbow and Igon's Bell Bearing.", warn:"", kind:"npc", master:"M10", px:6875.3, py:6456.5 },
  ]},
  { id:"hornsent", name:"Hornsent", color:"#b0884a", steps:[
    { n:1, title:"Meet Hornsent in Gravesite Plain", desc:"Speak with the vengeful pilgrim Hornsent at the first cross and exhaust his dialogue to receive the Cross Map marking Miquella's path.", warn:"", kind:"npc", master:"M10", px:4729.7, py:5659.3 },
    { n:2, title:"Defeat the Divine Beast Dancing Lion", desc:"Clear Belurat, Tower Settlement's boss to obtain the Divine Beast Head needed for the Hornsent Grandam exchange.", warn:"", kind:"boss", master:"M10", px:4289, py:5258.4 },
    { n:3, title:"Give the Divine Beast Head to Hornsent Grandam", desc:"Equip the Divine Beast Head and speak to Hornsent Grandam in her room by the grace to receive the Watchful Spirit incantation.", warn:"Get Watchful Spirit from Grandam (Divine Beast Head equipped) BEFORE killing Messmer; afterward she won't give the incantation.", kind:"npc", master:"M10", px:4315, py:5495.2 },
    { n:4, title:"Trade Scorpion Stew to Hornsent (optional)", desc:"Bring Scorpion Stew to Hornsent at the Three-Path Cross to receive three Furnace Visages in an optional exchange.", warn:"", kind:"npc", master:"M10", px:4729.7, py:5659.3 },
    { n:5, title:"Meet Hornsent again in Scadu Altus", desc:"Find Hornsent relocated to Highroad Cross north of Castle Ensis and exhaust his dialogue to receive the New Cross Map.", warn:"", kind:"npc", master:"M10", px:5230.1, py:5099.6 },
    { n:6, title:"Advance the story toward Shadow Keep", desc:"Progress to Shadow Keep, then return and rest at Highroad Cross so that Hornsent departs and Leda begins confronting him.", warn:"Do NOT enter Messmer's arena from the Dark Chamber grace until steps 5-9 are done; doing so removes Hornsent's and Leda's summon signs.", kind:"grace", master:"M10", px:5226.1, py:5108.2 },
    { n:7, title:"Side with Hornsent against Leda", desc:"At the burning boats near the Main Gate Plaza, choose the gold summon sign to fight Needle Knight Leda alongside Hornsent.", warn:"Choosing Hornsent's gold sign permanently locks out Leda's-side rewards (Lacerating/Retaliatory Crossed-Tree, Ansbach's Longbow). Exclusive branch.", kind:"grace", master:"M10", px:5359.4, py:4526.4 },
    { n:8, title:"Claim the reward for aiding Hornsent", desc:"After the victory, collect Ash of War: Swift Slash and Leda's Rune for siding with Hornsent.", warn:"", kind:"item", master:"M10", px:5359.4, py:4526.4 },
    { n:9, title:"Summon Hornsent against Messmer", desc:"Use Hornsent's gold summon sign inside the boss arena to fight Messmer the Impaler together.", warn:"Summon Hornsent's gold sign on your FIRST entry to Messmer's arena; entering without him erases the sign and forfeits this co-op step.", kind:"grace", master:"M10", px:5381.4, py:4264 },
    { n:10, title:"Hear Hornsent's vow of vengeance", desc:"Rest at Messmer's Dark Chamber and speak to Hornsent in the arena, where he vows to slay Marika and all of the Erdtree's kin.", warn:"", kind:"npc", master:"M10", px:5391.4, py:4306.5 },
    { n:11, title:"Defeat the invading Hornsent", desc:"On the rot-covered stairs before the Church of the Bud in the Ancient Ruins of Rauh, defeat Hornsent when he invades as a red phantom.", warn:"", kind:"npc", master:"M10", px:4147.7, py:4738.3 },
    { n:12, title:"Collect Hornsent's gear", desc:"Loot the Falx sword and the full Hornsent armor set from his remains to complete the questline.", warn:"", kind:"item", master:"M01", px:2709.4, py:4235.2 },
  ]},
  { id:"leda", name:"Needle Knight Leda and the Band", color:"#c9a341", steps:[
    { n:1, title:"Enter the Land of Shadow", desc:"Speak with Needle Knight Leda beside Miquella's withered arm at the Cocoon of the Empyrean in Mohgwyn Palace and touch the arm to be carried into the Realm of Shadow.", warn:"", kind:"grace", master:"M01", px:5548.2, py:6790.2 },
    { n:2, title:"Read Leda's first message", desc:"After defeating the Divine Beast Dancing Lion in Belurat, ride the arena elevator up and find Leda's written message declaring she pursues Miquella.", warn:"", kind:"boss", master:"M10", px:4289, py:5258.4 },
    { n:3, title:"Read Leda's second message", desc:"Find Leda's follow-up message at Miquella's Cross near the Castle Ensis Checkpoint grace indicating she is bound for the Shadow Keep.", warn:"", kind:"grace", master:"M10", px:5071, py:5169.5 },
    { n:4, title:"Meet the band at Highroad Cross", desc:"Speak with Needle Knight Leda beside the Highroad Cross grace in Scadu Altus, where she has gathered Miquella's followers, and exhaust her dialogue.", warn:"", kind:"npc", master:"M10", px:5185.7, py:5233.9 },
    { n:5, title:"Exhaust the gathered followers", desc:"Speak with the other followers assembled near Leda, including Dryleaf Dane, Hornsent, Thiollier, Sir Ansbach and Moore, to advance their interlinked questlines.", warn:"Exhaust all followers' dialogue (Hornsent, Ansbach, Thiollier, etc.) at Highroad Cross BEFORE breaking Miquella's charm, or you lose quest progress.", kind:"npc", master:"M10", px:5457.9, py:5131.1 },
    { n:6, title:"Break Miquella's charm", desc:"Progress toward the Shadow Keep until the message 'Somewhere, a great rune has broken' appears, shedding Miquella's Great Rune and turning the charmed band against one another.", warn:"Reaching Shadow Keep breaks the charm and turns the band hostile. Finish all gathered-follower dialogues first; this gate is irreversible.", kind:"grace", master:"M10", px:5359.4, py:4526.4 },
    { n:7, title:"Return to Leda after the charm breaks", desc:"Speak with Needle Knight Leda again at Highroad Cross, where she now suspects the band of treachery and asks whom she should investigate.", warn:"", kind:"npc", master:"M10", px:5185.7, py:5233.9 },
    { n:8, title:"Duel over Hornsent", desc:"On the boat-lined battlements before the Storehouse elevator in Shadow Keep, choose a red summon sign to aid Leda in slaying Hornsent or a gold sign to defend Hornsent against her.", warn:"Resolve this duel BEFORE entering Messmer's arena from Dark Chamber: the summon signs vanish there, permanently locking you out of this choice.  Â·  Helping Leda kills Hornsent for his set + talisman; defending him gives Swift Slash + Leda's Rune. Each choice permanently locks out the other's rewards.", kind:"npc", master:"M10", px:5391.4, py:4306.5 },
    { n:9, title:"Find Ansbach in the library", desc:"Progress Sir Ansbach's quest until he appears in the Storehouse library and exhaust his dialogue to set up Leda's next confrontation.", warn:"", kind:"npc", master:"M10", px:5534.6, py:4312 },
    { n:10, title:"Duel over Ansbach", desc:"If you sided with Leda against Hornsent, choose the red summon sign to help Leda kill Ansbach or the gold sign to defend him so he survives for Enir-Ilim.", warn:"Picking the red sign to help Leda kills Ansbach permanently, losing the Obsidian Lamina and Furious Blade of Ansbach. Use the gold sign to save him.  Â·  This duel only appears if you sided with Leda against Hornsent in step 8; otherwise Leda never invades Ansbach and this step is skipped.", kind:"npc", master:"M10", px:4148.5, py:5259.7 },
    { n:11, title:"Confront the band at Enir-Ilim", desc:"At the Cleansing Chamber Anteroom, advance into the open hall where Leda accuses you of seeking the Erdtree's throne and stages the final ambush.", warn:"", kind:"grace", master:"M10", px:4029.7, py:5374.1 },
    { n:12, title:"Defeat Leda and her allies", desc:"Kill Needle Knight Leda and her hostile companions (Dryleaf Dane plus, by your earlier choices, Freyja, Moore and Hornsent) while any saved allies like Ansbach or Thiollier fight at your side.", warn:"", kind:"npc", master:"M10", px:4133.6, py:5399.7 },
    { n:13, title:"Loot Leda's gear", desc:"Retrieve Leda's Sword from her body after the Enir-Ilim battle to claim her signature holy greatsword.", warn:"", kind:"item", master:"M10", px:4029.7, py:5374.1 },
    { n:14, title:"Claim Leda's armor", desc:"Collect Leda's Armor from her corpse to obtain her unique chest piece and conclude the questline.", warn:"", kind:"item", master:"M01", px:2709.4, py:4235.2 },
  ]},
  { id:"varre", name:"White Mask Varré", color:"#b03a48", steps:[
    { n:1, title:"Meet Varré at the start", desc:"At the very beginning of the game, White Mask Varré stands near The First Step and the Church of Elleh, mocking you as a Tarnished and pointing you toward Stormveil and Roundtable Hold. Speak with him to begin his questline.", warn:"", kind:"npc", master:"M00", px:3695, py:7343.9 },
    { n:2, title:"Obtain a Great Rune, then meet him at Rose Church", desc:"After defeating a shardbearer for a Great Rune and speaking with Enia at Roundtable Hold, Varré relocates to Rose Church in southwest Liurnia. Speak to him there to continue.", warn:"Varré only moves to Rose Church after you acquire a Great Rune and talk to Enia; if you ignore him too long across major story beats he can vanish, breaking the quest.", kind:"npc", master:"M00", px:1848.9, py:5344.7 },
    { n:3, title:"Accept the Festering Bloody Finger", desc:"Continue talking to Varré at Rose Church until he gives you a Festering Bloody Finger, inviting you into the 'fingers' and the service of Mohg, Lord of Blood.", warn:"", kind:"item", master:"M00", px:1848.9, py:5344.7 },
    { n:4, title:"Invade other Tarnished three times", desc:"Use the Festering Bloody Finger to invade three other players; you only need to take part, not win. If you prefer offline, invade the NPC red sign of Magnus the Beast Claw at Writheblood Ruins three times instead.", warn:"The offline NPC sign at Writheblood Ruins is the reliable way to complete this; co-op invasions require an online connection.", kind:"npc", master:"M00", px:1848.9, py:5344.7 },
    { n:5, title:"Receive the Lord of Blood's Favor", desc:"Report back to Varré after the invasions and he hands you the Lord of Blood's Favor, a white cloth he asks you to soak in the blood of a maiden.", warn:"", kind:"item", master:"M00", px:1848.9, py:5344.7 },
    { n:6, title:"Soak the cloth in maiden's blood", desc:"Take the Lord of Blood's Favor to a dead Finger Maiden and use it from your inventory to soak it in her blood. The corpse at the altar of the Church of Inhibition works, as do the maiden at the Chapel of Anticipation or a slain Hyetta.", warn:"You must 'Use' the cloth at the maiden's body to soak it; simply visiting does nothing. Killing Hyetta to soak it will end her own questline.", kind:"grace", master:"M00", px:2508.3, py:3995 },
    { n:7, title:"Return the bloody cloth for the Bloody Finger", desc:"Bring the soaked Lord of Blood's Favor back to Varré at Rose Church. He rewards you with the reusable Bloody Finger, letting you invade freely without consuming an item.", warn:"", kind:"item", master:"M00", px:2508.3, py:3995 },
    { n:8, title:"Receive the Pureblood Knight's Medal", desc:"Speak with Varré once more after handing over the cloth. He recognizes you as kin and gives you the Pureblood Knight's Medal, your invitation to Mohgwyn Palace.", warn:"This is the final reward of Varré's quest; obtain it before deciding whether to kill him, as his hostile turn occurs only if you attack him afterward.", kind:"item", master:"M00", px:2508.3, py:3995 },
    { n:9, title:"Use the Medal to reach Mohgwyn Palace", desc:"Use the Pureblood Knight's Medal from your inventory to teleport directly into Mohgwyn Palace, arriving at near the Dynasty Mausoleum Midpoint grace in the far northeast of the underworld.", warn:"Using the Medal is the early shortcut into Mohgwyn Palace; the only other entrance is a hidden teleporter in the Consecrated Snowfield much later in the game.", kind:"grace", master:"M01", px:5653.2, py:6785.2 },
    { n:10, title:"Confront Mohg, Lord of Blood", desc:"Press deeper into Mohgwyn Palace to the Cocoon of the Empyrean and challenge Mohg, Lord of Blood, the demigod Varré served. Defeating him yields Mohg's Great Rune and his Remembrance of the Blood Lord.", warn:"", kind:"boss", master:"M01", px:5568.5, py:6799.6 },
  ]},
  { id:"rogier", name:"Sorcerer Rogier", color:"#5a7fd0", steps:[
    { n:1, title:"Meet Rogier in Stormveil", desc:"Find Sorcerer Rogier seated at the ruined chapel altar in the northwest of Stormveil Castle. Exhaust his dialogue; he can also be summoned for the Margit fight via his sign nearby.", warn:"", kind:"npc", master:"M00", px:3058, py:6632.1 },
    { n:2, title:"Rogier moves to Roundtable", desc:"After you defeat Godrick the Grafted, Rogier relocates to a chair on the balcony of Roundtable Hold and gives you Rogier's Rapier with the Glintblade Phalanx ash of war.", warn:"", kind:"npc", master:"M00", px:2858.3, py:7606.6 },
    { n:3, title:"The corpse beneath Stormveil", desc:"Drop down beneath Stormveil from the Liftside Chamber grace, defeat the Ulcerated Tree Spirit, then touch the bloodstain before the giant rotting face (Godwyn) to inspect the Black Knife relic.", warn:"The Ulcerated Tree Spirit here (b18000800) guards the corpse; you must interact with the bloodstain to advance the quest, not just kill the boss.", kind:"boss", master:"M00", px:3888.5, py:7344.5 },
    { n:4, title:"Report the relic to Rogier", desc:"Return to Rogier at Roundtable Hold and exhaust his dialogue. He explains the corpse is tied to the Black Knives' plot and the assassination of Godwyn.", warn:"", kind:"npc", master:"M00", px:2858.3, py:7606.6 },
    { n:5, title:"Ask Fia about the Knifeprint", desc:"Speak with Fia, the Deathbed Companion at Roundtable Hold and exhaust her dialogue to receive the Knifeprint Clue, which points to the Black Knife Catacombs.", warn:"", kind:"npc", master:"M00", px:2880.7, py:7627.1 },
    { n:6, title:"Retrieve the Black Knifeprint", desc:"Travel to the Black Knife Catacombs in northern Limgrave, open the boss room, and defeat the Black Knife Assassin to claim the Black Knifeprint.", warn:"Use the assassin inside Black Knife Catacombs (b30110800); the Knifeprint is the quest item, so be sure to loot the chest/room afterward.", kind:"boss", master:"M00", px:2718.2, py:4207.1 },
    { n:7, title:"Bring the Knifeprint to Rogier", desc:"Return to Rogier at Roundtable Hold with the Black Knifeprint. He analyzes it and concludes Ranni the Witch was behind the Night of the Black Knives.", warn:"", kind:"npc", master:"M00", px:2858.3, py:7606.6 },
    { n:8, title:"Seek out Ranni", desc:"Visit Ranni the Witch atop Ranni's Rise in the Three Sisters, northwest Liurnia. She brushes you off, so the conversation only sets up Rogier's next request.", warn:"Do not begin Ranni's vassal service until Rogier asks you to; talking to Ranni alone is fine, but advancing her quest early then resting can trigger Rogier's slumber.", kind:"npc", master:"M00", px:1611.3, py:3686.4 },
    { n:9, title:"Rogier asks you to serve Ranni", desc:"Report back to Rogier at Roundtable Hold. He asks you to become Ranni's vassal to investigate further, then warns he is about to fall into a deep slumber.", warn:"", kind:"npc", master:"M00", px:2858.3, py:7606.6 },
    { n:10, title:"Collect the Spellblade Set", desc:"Progress Ranni's questline and rest at Roundtable Hold; Rogier falls asleep and dies. Loot his chair to obtain the Spellblade's Set and Rogier's Bell Bearing.", warn:"", kind:"npc", master:"M00", px:2858.3, py:7606.6 },
  ]},
  { id:"dragoncommunion", name:"Dragon Communion Priestess (Florissax)", color:"#c08a3e", steps:[
    { n:1, title:"Meet Florissax", desc:"Reach the Grand Altar of Dragon Communion at the Foot of the Jagged Peak and speak with the Dragon Communion Priestess. Accept 'Devour draconic essence' to receive the Ancient Dragon's Blessing, then exhaust her dialogue about Bayle.", warn:"", kind:"npc", master:"M10", px:5584.2, py:6623.1 },
    { n:2, title:"Get Black Syrup from Moore", desc:"Travel to the Gravesite Plain and find Moore near Main Gate Cross. Exhaust his dialogue across his quest until he gives you the Black Syrup.", warn:"Missable: progress Moore's quest and collect Black Syrup before he despairs and leaves, or you cannot make the Concoction.", kind:"npc", master:"M10", px:4377.7, py:5666.1 },
    { n:3, title:"Make Thiollier's Concoction", desc:"Bring the Black Syrup to Thiollier and give it to him. He brews it into Thiollier's Concoction, the sleep elixir Florissax needs.", warn:"Missable: requires Thiollier's questline progress; advance his quest before he relocates or the Concoction is lost.", kind:"npc", master:"M10", px:4145.1, py:5259.7 },
    { n:4, title:"Catch Florissax at night", desc:"Pass time at a distant Site of Grace until nightfall, then return to the Grand Altar. Find Florissax praying to Placidussax and give her Thiollier's Concoction, putting her to sleep.", warn:"Missable: she only prays at night and only before Bayle is killed. Do this BEFORE defeating Bayle or the spirit ash reward is lost forever.", kind:"grace", master:"M10", px:5596.3, py:6623.2 },
    { n:5, title:"Wait one day cycle", desc:"After she falls asleep, pass one full in-game day at a Site of Grace, then return to the altar so she stirs and the quest can continue.", warn:"", kind:"grace", master:"M10", px:5596.3, py:6623.2 },
    { n:6, title:"Climb the Jagged Peak", desc:"From the Foot of the Jagged Peak, ascend the mountain past the Jagged Peak Drakes, resting at the Jagged Peak Mountainside grace along the way.", warn:"", kind:"grace", master:"M10", px:6776.4, py:6227.3 },
    { n:7, title:"Reach the summit", desc:"Continue to the Jagged Peak Summit grace at the top of the mountain, the gateway to Bayle's lair below.", warn:"", kind:"grace", master:"M10", px:6827.5, py:6428.2 },
    { n:8, title:"Defeat Bayle the Dread", desc:"Drop into the lair and slay Bayle the Dread, the ancient dragon Florissax reveres. Summon Igon for his dialogue and loot if desired.", warn:"", kind:"boss", master:"M10", px:6896, py:6502 },
    { n:9, title:"Return for Dragonbolt", desc:"Fast travel back to the Grand Altar of Dragon Communion and speak with Florissax. She rewards you with the Dragonbolt of Florissax incantation.", warn:"", kind:"npc", master:"M10", px:5584.2, py:6623.1 },
    { n:10, title:"Confess and claim Florissax", desc:"Talk to her again, confess that you put her to sleep, and accept becoming her lord. She pledges herself, transforming into the Ancient Dragon Florissax spirit ashes left at the altar.", warn:"Only available if you gave her the Concoction before killing Bayle. If you skipped the Concoction, you instead receive the Priestess Heart and Flowerstone Gavel here.", kind:"grace", master:"M10", px:5596.3, py:6623.2 },
  ]},
  { id:"gurranq", name:"Gurranq, Beast Clergyman", color:"#7a6b3a", steps:[
    { n:1, title:"Get your first Deathroot", desc:"Defeat the Tibia Mariner at Summonwater Village in northeast Limgrave to claim an early Deathroot. Deathroot also drops from other Tibia Mariners and certain bosses across the Lands Between.", warn:"", kind:"boss", master:"M00", px:4445, py:6526.7 },
    { n:2, title:"Reach the Bestial Sanctum", desc:"Travel to the Bestial Sanctum in Greyoll's Dragonbarrow, in the far east. Early on it is reached via the teleporter chest in the Fringefolk Hero's Cave at the Stranded Graveyard.", warn:"The Fringefolk Hero's Cave teleporter chest is behind a fog wall that needs 2 Stonesword Keys and flings you deep into high-level Dragonbarrow - a known trap.", kind:"grace", master:"M00", px:5968.9, py:5488.4 },
    { n:3, title:"Feed the first Deathroot", desc:"Give a Deathroot to Gurranq, the Beast Clergyman, beside the sanctum grace. He rewards the Clawmark Seal and the Beast Eye, which pulses when Deathroot is near.", warn:"", kind:"npc", master:"M00", px:5943.5, py:5473.6 },
    { n:4, title:"Second Deathroot", desc:"Return with another Deathroot for the Bestial Sling incantation.", warn:"", kind:"npc", master:"M00", px:5943.5, py:5473.6 },
    { n:5, title:"Third Deathroot", desc:"A third Deathroot earns the Beast Claw incantation.", warn:"", kind:"npc", master:"M00", px:5943.5, py:5473.6 },
    { n:6, title:"Fourth Deathroot", desc:"A fourth Deathroot grants the Stone of Gurranq incantation.", warn:"After the fourth Deathroot, Gurranq turns hostile the next time you visit (reload the area) - you must fight him.", kind:"npc", master:"M00", px:5943.5, py:5473.6 },
    { n:7, title:"Pacify Gurranq, then keep feeding", desc:"Lower Gurranq's health until he relents - do NOT finish him. Once calmed, further Deathroots reward Beast's Roar and then Gurranq's Beast Claw.", warn:"Do not kill Gurranq - killing him ends the quest and forfeits the remaining incantations.", kind:"npc", master:"M00", px:5943.5, py:5473.6 },
  ]},
];

